window.trendingPapers = {
    "today": [{"paper": {"id": "2606.22388", "authors": [{"_id": "6a39f5e9fdcd3514343bb51d", "user": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "isPro": false, "fullname": "Jeff", "user": "JiayuJeff", "type": "user", "name": "JiayuJeff"}, "name": "Jiayu Liu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:50.325Z", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb51e", "name": "Qihan Lin", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb51f", "name": "Cheng Qian", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb520", "name": "Rui Wang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb521", "name": "Emre Can Acikgoz", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb522", "name": "Xiaocheng Yang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb523", "name": "Jiateng Liu", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb524", "name": "Zhenhailong Wang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb525", "name": "Xiusi Chen", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb526", "name": "Heng Ji", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb527", "name": "Dilek Hakkani-T\u00fcr", "hidden": false}], "publishedAt": "2026-06-21T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "PlanBench-XL: Evaluating Long-Horizon Planning of LLM Tool-Use Agents in Large-Scale Tool Ecosystems", "submittedOnDailyBy": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "isPro": false, "fullname": "Jeff", "user": "JiayuJeff", "type": "user", "name": "JiayuJeff"}, "summary": "LLM agents increasingly operate in large tool ecosystems, where real-world tasks require discovering relevant tools, inferring implicit sub-goals, and adapting to dynamic environments over long horizons. However, existing benchmarks rarely evaluate planning under retrieval-limited tool visibility. To address this gap, we introduce PlanBench-XL, an interactive benchmark of 327 retail tasks over 1,665 tools that tests whether agents can iteratively retrieve usable tools, invoke them to uncover intermediate evidence for subsequent calls toward the final goal. PlanBench-XL further features an optional blocking mechanism that simulates real-world unpredictability through missing, failing, or distracting tool functions, forcing agents to detect disrupted paths and adapt at runtime. Experiments on ten leading LLMs show that massive-tool planning remains challenging: while GPT-5.4 achieves 51.90% accuracy in block-free settings, it collapses to 11.36% under the most severe blocking condition. Further analysis shows that agents are especially vulnerable when failures lack explicit error signals or when recovery requires longer alternative tool-use paths. These results establish PlanBench-XL as a testbed for diagnosing agentic planning failures and highlight the need for robust adaptive planning in long-horizon tasks with large, imperfect tool environments.", "upvotes": 79, "discussionId": "6a39f5eafdcd3514343bb528", "projectPage": "https://planbench-xl.github.io/", "githubRepo": "https://github.com/JiayuJeff/PlanBench-XL", "githubRepoAddedBy": "user", "ai_summary": "PlanBench-XL evaluates large language model agents' ability to plan and adapt in complex tool-rich environments with limited visibility and dynamic disruptions.", "ai_keywords": ["LLM agents", "tool ecosystems", "planning", "retrieval-limited tool visibility", "interactive benchmark", "tool discovery", "implicit sub-goals", "dynamic environments", "long horizons", "blocking mechanism", "agent adaptation", "tool-use paths", "agentic planning", "robust planning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 26, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86PlanBench-XL\uff0c\u8fd9\u662f\u4e00\u4e2a\u5305\u542b327\u4e2a\u96f6\u552e\u4efb\u52a1\u548c1,665\u4e2a\u5de5\u5177\u7684\u4e92\u52a8\u57fa\u51c6\u6d4b\u8bd5\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u6d4b\u8bd5\u8bc4\u4f30\u4ee3\u7406\u5728\u6709\u9650\u5de5\u5177\u53ef\u89c1\u6027\u4e0b\u7684\u89c4\u5212\u80fd\u529b\uff0c\u662f\u5426\u80fd\u6709\u6548\u67e5\u627e\u548c\u4f7f\u7528\u5de5\u5177\u3002</li>\n    <li>PlanBench-XL\u6a21\u62df\u73b0\u5b9e\u4e16\u754c\u7684\u4e0d\u786e\u5b9a\u6027\uff0c\u4f8b\u5982\u5de5\u5177\u529f\u80fd\u7f3a\u5931\u6216\u5931\u8d25\uff0c\u8981\u6c42\u4ee3\u7406\u5728\u8fd0\u884c\u65f6\u9002\u5e94\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5c3d\u7ba1GPT-5.4\u5728\u6ca1\u6709\u963b\u585e\u7684\u60c5\u51b5\u4e0b\u670951.90%\u7684\u51c6\u786e\u7387\uff0c\u4f46\u5728\u6700\u4e25\u91cd\u7684\u963b\u585e\u6761\u4ef6\u4e0b\u51c6\u786e\u7387\u964d\u81f311.36%\u3002</li>\n    <li>\u7ed3\u679c\u8868\u660e\uff0c\u4ee3\u7406\u5728\u9762\u5bf9\u7f3a\u4e4f\u660e\u786e\u9519\u8bef\u4fe1\u53f7\u7684\u5931\u8d25\u65f6\uff0c\u5bb9\u6613\u53d7\u5230\u5f71\u54cd\uff0c\u5f3a\u8c03\u4e86\u5728\u5927\u578b\u4e0d\u5b8c\u7f8e\u5de5\u5177\u73af\u5883\u4e2d\u8fdb\u884c\u7a33\u5065\u9002\u5e94\u6027\u89c4\u5212\u7684\u5fc5\u8981\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>PlanBench-XL is a new benchmark designed to test LLM agents on 327 retail tasks using 1,665 tools.</li>\n    <li>It evaluates how well agents can find and use tools, adapt to changing situations, and handle unexpected problems.</li>\n    <li>The benchmark includes a feature that simulates real-world challenges, such as tools failing or not working as expected.</li>\n    <li>Experiments show that even advanced models like GPT-5.4 struggle with planning when faced with tool disruptions.</li>\n    <li>The findings highlight the need for better adaptive planning in complex environments with many tools.</li>\n</ul>"}, "publishedAt": "2026-06-20T20:00:00.000Z", "title": "PlanBench-XL: Evaluating Long-Horizon Planning of LLM Tool-Use Agents in Large-Scale Tool Ecosystems", "summary": "LLM agents increasingly operate in large tool ecosystems, where real-world tasks require discovering relevant tools, inferring implicit sub-goals, and adapting to dynamic environments over long horizons. However, existing benchmarks rarely evaluate planning under retrieval-limited tool visibility. To address this gap, we introduce PlanBench-XL, an interactive benchmark of 327 retail tasks over 1,665 tools that tests whether agents can iteratively retrieve usable tools, invoke them to uncover intermediate evidence for subsequent calls toward the final goal. PlanBench-XL further features an optional blocking mechanism that simulates real-world unpredictability through missing, failing, or distracting tool functions, forcing agents to detect disrupted paths and adapt at runtime. Experiments on ten leading LLMs show that massive-tool planning remains challenging: while GPT-5.4 achieves 51.90% accuracy in block-free settings, it collapses to 11.36% under the most severe blocking condition. Further analysis shows that agents are especially vulnerable when failures lack explicit error signals or when recovery requires longer alternative tool-use paths. These results establish PlanBench-XL as a testbed for diagnosing agentic planning failures and highlight the need for robust adaptive planning in long-horizon tasks with large, imperfect tool environments.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22388.png", "numComments": 3, "submittedBy": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "fullname": "Jeff", "name": "JiayuJeff", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.19409", "authors": [{"_id": "6a362251db23715e9da12e25", "user": {"_id": "68f792b148e9f4a46eca68bf", "avatarUrl": "/avatars/a6442a2777a4b7e78f01168b80847446.svg", "isPro": false, "fullname": "Fukang Wen", "user": "smallkang2025", "type": "user", "name": "smallkang2025"}, "name": "Fukang Wen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-22T16:14:27.169Z", "hidden": false}, {"_id": "6a362251db23715e9da12e26", "name": "Zhijie Wang", "hidden": false}, {"_id": "6a362251db23715e9da12e27", "name": "Ruilin Xu", "hidden": false}], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "OpenRath: Session-Centered Runtime State for Agent Systems", "submittedOnDailyBy": {"_id": "68f792b148e9f4a46eca68bf", "avatarUrl": "/avatars/a6442a2777a4b7e78f01168b80847446.svg", "isPro": false, "fullname": "Fukang Wen", "user": "smallkang2025", "type": "user", "name": "smallkang2025"}, "summary": "Modern agent systems often suffer from fragmented runtime state: transcripts, tool effects, memory events, workspace placement, branch provenance, and replay evidence are recorded separately and become difficult to inspect or reproduce. OpenRath addresses this issue with a PyTorch-like programming model for multi-agent, multi-session systems. The analogy concerns the role of a central first-class runtime abstraction, not tensor computation. Its core abstraction is Session, the runtime value passed between agents and workflows. A Session is branchable, inspectable, replayable, backend-aware, and composable. It records conversation chunks, sandbox placement, lineage metadata, token usage, pending work, and tool evidence, while defining where memory interactions enter the runtime record. Since this state is carried by the same value used in program execution, fork, merge, and replay become explicit runtime operations rather than states reconstructed from external traces. OpenRath further defines Sandbox, Tool, Agent, Memory, Workflow, and Selector, with Selector turning control flow into runtime-routed decisions. This report presents the programming model, architecture, audited milestones, and evidence protocol. Its claims are limited to controlled runtime properties, while broad quantitative comparisons, live-provider quality, optional-backend availability, and memory quality are left for follow-on evaluation. The central thesis is that Session provides agent systems with a first-class runtime value for auditable composition.", "upvotes": 68, "discussionId": "6a362251db23715e9da12e28", "projectPage": "https://docs.openrath.com", "githubRepo": "https://github.com/Rath-Team/OpenRath", "githubRepoAddedBy": "user", "ai_summary": "OpenRath introduces a PyTorch-like programming model for multi-agent systems using Session as a central runtime abstraction that enables explicit fork, merge, and replay operations while recording comprehensive execution state.", "ai_keywords": ["Session", "Sandbox", "Tool", "Agent", "Memory", "Workflow", "Selector", "runtime abstraction", "fork", "merge", "replay", "auditable composition", "execution state"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 672, "summary_zh": "<ul>\n    <li>\u73b0\u4ee3\u667a\u80fd\u4f53\u7cfb\u7edf\u5e38\u5e38\u9762\u4e34\u8fd0\u884c\u72b6\u6001\u5206\u6563\u7684\u95ee\u9898\uff0c\u96be\u4ee5\u68c0\u67e5\u6216\u91cd\u73b0\u3002</li>\n    <li>OpenRath \u63d0\u4f9b\u4e86\u4e00\u79cd\u7c7b\u4f3c\u4e8e PyTorch \u7684\u7f16\u7a0b\u6a21\u578b\uff0c\u65e8\u5728\u89e3\u51b3\u591a\u667a\u80fd\u4f53\u3001\u591a\u4f1a\u8bdd\u7cfb\u7edf\u7684\u6311\u6218\u3002</li>\n    <li>\u5176\u6838\u5fc3\u6982\u5ff5\u662f\u201c\u4f1a\u8bdd\u201d\uff08Session\uff09\uff0c\u7528\u4e8e\u5728\u667a\u80fd\u4f53\u548c\u5de5\u4f5c\u6d41\u4e4b\u95f4\u4f20\u9012\u8fd0\u884c\u65f6\u503c\u3002</li>\n    <li>\u4f1a\u8bdd\u53ef\u4ee5\u5206\u652f\u3001\u68c0\u67e5\u3001\u91cd\u653e\uff0c\u5e76\u8bb0\u5f55\u5bf9\u8bdd\u7247\u6bb5\u3001\u6c99\u7bb1\u4f4d\u7f6e\u3001\u5143\u6570\u636e\u7b49\u4fe1\u606f\u3002</li>\n    <li>OpenRath \u8fd8\u5b9a\u4e49\u4e86\u6c99\u7bb1\u3001\u5de5\u5177\u3001\u667a\u80fd\u4f53\u3001\u5185\u5b58\u3001\u5de5\u4f5c\u6d41\u548c\u9009\u62e9\u5668\u7b49\u6982\u5ff5\uff0c\u4f7f\u63a7\u5236\u6d41\u6210\u4e3a\u8fd0\u884c\u65f6\u51b3\u7b56\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>OpenRath solves the problem of fragmented state in modern agent systems by introducing a new programming model.</li>\n    <li>A central concept called \"Session\" is used to manage and track state across different agents and workflows.</li>\n    <li>Sessions are designed to be easily inspected, replayed, and modified, making it simpler to manage conversations and tool use.</li>\n    <li>The system includes additional components like Sandbox, Tool, Agent, Memory, Workflow, and Selector to enhance functionality.</li>\n    <li>This report discusses the programming model and architecture, while suggesting further evaluation on specific performance aspects.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "OpenRath: Session-Centered Runtime State for Agent Systems", "summary": "Modern agent systems often suffer from fragmented runtime state: transcripts, tool effects, memory events, workspace placement, branch provenance, and replay evidence are recorded separately and become difficult to inspect or reproduce. OpenRath addresses this issue with a PyTorch-like programming model for multi-agent, multi-session systems. The analogy concerns the role of a central first-class runtime abstraction, not tensor computation. Its core abstraction is Session, the runtime value passed between agents and workflows. A Session is branchable, inspectable, replayable, backend-aware, and composable. It records conversation chunks, sandbox placement, lineage metadata, token usage, pending work, and tool evidence, while defining where memory interactions enter the runtime record. Since this state is carried by the same value used in program execution, fork, merge, and replay become explicit runtime operations rather than states reconstructed from external traces. OpenRath further defines Sandbox, Tool, Agent, Memory, Workflow, and Selector, with Selector turning control flow into runtime-routed decisions. This report presents the programming model, architecture, audited milestones, and evidence protocol. Its claims are limited to controlled runtime properties, while broad quantitative comparisons, live-provider quality, optional-backend availability, and memory quality are left for follow-on evaluation. The central thesis is that Session provides agent systems with a first-class runtime value for auditable composition.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19409.png", "numComments": 3, "submittedBy": {"_id": "68f792b148e9f4a46eca68bf", "avatarUrl": "/avatars/a6442a2777a4b7e78f01168b80847446.svg", "fullname": "Fukang Wen", "name": "smallkang2025", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.21337", "authors": [{"_id": "6a3a16b3fdcd3514343bb6a3", "user": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "isPro": false, "fullname": "Cong", "user": "Coneonewan", "type": "user", "name": "Coneonewan"}, "name": "Cong Wan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:05.018Z", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a4", "name": "Zeyu Guo", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a5", "name": "Zijian Cai", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a6", "name": "Jiangyang Li", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a7", "name": "SongLin Dong", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a8", "name": "Lin Peng", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a9", "user": {"_id": "668df98de9e585e8718f767f", "avatarUrl": "/avatars/2be52f4ae88a0991c8ae584f8e870734.svg", "isPro": false, "fullname": "Xiangyang Luo", "user": "XiangyangLuo02", "type": "user", "name": "XiangyangLuo02"}, "name": "Xiangyang Luo", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:01.079Z", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6aa", "name": "Zhiheng Ma", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6ab", "name": "Yihong Gong", "hidden": false}], "publishedAt": "2026-06-19T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "DataClaw0: Agentic Tailoring Multimodal Data from Raw Streams", "submittedOnDailyBy": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "isPro": false, "fullname": "Cong", "user": "Coneonewan", "type": "user", "name": "Coneonewan"}, "summary": "Massive unstructured multimodal streams suffer from high \"data entropy,\" impeding both efficient human knowledge acquisition and high-quality AI post-training. Existing passive annotation paradigms, heavily reliant on heuristic rules or general VLMs, are costly, monotonous, and fail to unlock the deep procedural logic embedded in raw data. We elevate data processing to a learnable capability, proposing a paradigm shift towards Agentic Data Tailoring, which actively refining and structuring data to align with diverse user and downstream intents. To overcome the data scarcity bottleneck in training such high-order capabilities, we design a two-stage pipeline grounding generative semantic synthesis in deterministic Factual Anchors, yielding a large-scale dataset spanning five core physical and digital domains. Building upon this, DataClaw_0-9B model synergizes Supervised Fine-Tuning (SFT) with Group Relative Policy Optimization (GRPO), achieving robust alignment with complex refinement and tailoring intents. To systematically quantify this capability, we construct DataClaw_0-val, the first benchmark dedicated to data refinement. Crucially, we adopt downstream post-training as the ultimate validation touchstone. Evaluations on video generation, real-world VQA, and GUI navigation confirm that DataClaw_0 delivers high-information-density tailored data, facilitating efficient model adaptation to new tasks under limited training data regimes. Project page: https://czjdsg.github.io/MakeAnyData", "upvotes": 65, "discussionId": "6a3a16b3fdcd3514343bb6ac", "projectPage": "https://czjdsg.github.io/MakeAnyData/#cases", "githubRepo": "https://github.com/vancyland/DataClaw0", "githubRepoAddedBy": "user", "ai_summary": "Agentic Data Tailoring paradigm uses learnable data processing to structure high-entropy multimodal streams, with DataClaw_0-9B model achieving robust alignment through SFT and GRPO on a novel benchmark.", "ai_keywords": ["Agentic Data Tailoring", "generative semantic synthesis", "deterministic Factual Anchors", "Supervised Fine-Tuning", "Group Relative Policy Optimization", "data refinement", "multimodal streams", "data entropy", "downstream post-training"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 24, "summary_zh": "<ul>\n    <li>\u5927\u91cf\u975e\u7ed3\u6784\u5316\u7684\u591a\u6a21\u6001\u6570\u636e\u5b58\u5728\u9ad8\u201c\u6570\u636e\u71b5\u201d\uff0c\u5f71\u54cd\u4eba\u7c7b\u77e5\u8bc6\u83b7\u53d6\u548cAI\u540e\u7eed\u8bad\u7ec3\u7684\u8d28\u91cf\u3002</li>\n    <li>\u73b0\u6709\u7684\u88ab\u52a8\u6ce8\u91ca\u65b9\u6cd5\u4f9d\u8d56\u542f\u53d1\u5f0f\u89c4\u5219\u6216\u901a\u7528\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff0c\u6210\u672c\u9ad8\u4e14\u6548\u7387\u4f4e\uff0c\u65e0\u6cd5\u6df1\u5165\u7406\u89e3\u539f\u59cb\u6570\u636e\u4e2d\u7684\u903b\u8f91\u3002</li>\n    <li>\u63d0\u51fa\u201c\u4e3b\u52a8\u6570\u636e\u5b9a\u5236\u201d\u7684\u65b0\u65b9\u6cd5\uff0c\u901a\u8fc7\u4e3b\u52a8\u6574\u7406\u6570\u636e\u6765\u6ee1\u8db3\u7528\u6237\u548c\u4e0b\u6e38\u9700\u6c42\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u4e00\u4e2a\u4e24\u9636\u6bb5\u6d41\u7a0b\uff0c\u5229\u7528\u786e\u5b9a\u6027\u4e8b\u5b9e\u951a\u70b9\u751f\u6210\u5927\u89c4\u6a21\u6570\u636e\u96c6\uff0c\u6db5\u76d6\u4e94\u4e2a\u6838\u5fc3\u9886\u57df\u3002</li>\n    <li>DataClaw_0-9B\u6a21\u578b\u7ed3\u5408\u76d1\u7763\u5fae\u8c03\u548c\u7ec4\u76f8\u5bf9\u7b56\u7565\u4f18\u5316\uff0c\u80fd\u6709\u6548\u652f\u6301\u590d\u6742\u6570\u636e\u7684\u7cbe\u7ec6\u5316\u548c\u5b9a\u5236\u4efb\u52a1\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Unstructured data has high \"data entropy,\" making it hard for humans and AI to learn from it effectively.</li>\n    <li>Current data annotation methods are expensive and don't fully utilize the information in raw data.</li>\n    <li>We propose a new method called Agentic Data Tailoring that actively organizes data to meet different user needs.</li>\n    <li>We created a two-stage process to generate a large dataset that helps train advanced data processing models.</li>\n    <li>The DataClaw_0-9B model improves how AI can adapt to new tasks using tailored data, as shown in various evaluations.</li>\n</ul>"}, "publishedAt": "2026-06-18T20:00:00.000Z", "title": "DataClaw0: Agentic Tailoring Multimodal Data from Raw Streams", "summary": "Massive unstructured multimodal streams suffer from high \"data entropy,\" impeding both efficient human knowledge acquisition and high-quality AI post-training. Existing passive annotation paradigms, heavily reliant on heuristic rules or general VLMs, are costly, monotonous, and fail to unlock the deep procedural logic embedded in raw data. We elevate data processing to a learnable capability, proposing a paradigm shift towards Agentic Data Tailoring, which actively refining and structuring data to align with diverse user and downstream intents. To overcome the data scarcity bottleneck in training such high-order capabilities, we design a two-stage pipeline grounding generative semantic synthesis in deterministic Factual Anchors, yielding a large-scale dataset spanning five core physical and digital domains. Building upon this, DataClaw_0-9B model synergizes Supervised Fine-Tuning (SFT) with Group Relative Policy Optimization (GRPO), achieving robust alignment with complex refinement and tailoring intents. To systematically quantify this capability, we construct DataClaw_0-val, the first benchmark dedicated to data refinement. Crucially, we adopt downstream post-training as the ultimate validation touchstone. Evaluations on video generation, real-world VQA, and GUI navigation confirm that DataClaw_0 delivers high-information-density tailored data, facilitating efficient model adaptation to new tasks under limited training data regimes. Project page: https://czjdsg.github.io/MakeAnyData", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.21337.png", "numComments": 1, "submittedBy": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "fullname": "Cong", "name": "Coneonewan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.23654", "authors": [{"_id": "6a3a0213fdcd3514343bb586", "name": "Jincheng Zhong", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb587", "name": "Weizhi Wang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb588", "name": "Che Jiang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb589", "name": "Kai Tian", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58a", "name": "Zhenzhao Yuan", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58b", "name": "Junlin Yang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58c", "name": "Dianqiao Lei", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58d", "user": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "name": "Kaiyan Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:30.920Z", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "submittedOnDailyBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "upvotes": 57, "discussionId": "6a3a0213fdcd3514343bb58e", "projectPage": "https://frontisai.github.io/EnterpriseClawBench/", "githubRepo": "https://github.com/FrontisAI/EnterpriseClawBench", "githubRepoAddedBy": "user", "ai_summary": "EnterpriseClawBench presents a benchmark for enterprise agents based on real-world sessions with 852 reproducible tasks, emphasizing comprehensive evaluation metrics beyond single performance scores.", "ai_keywords": ["enterprise agent benchmark", "reproducible tasks", "workplace sessions", "harness--model combinations", "artifact delivery", "skill-transfer behavior"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 28, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "summary_zh": "<ul>\n    <li>EnterpriseClawBench\u662f\u4e00\u4e2a\u7528\u4e8e\u4f01\u4e1a\u4ee3\u7406\u7684\u57fa\u51c6\u6d4b\u8bd5\uff0c\u57fa\u4e8e\u771f\u5b9e\u7684\u5de5\u4f5c\u573a\u6240\u4f1a\u8bdd\u6784\u5efa\u3002</li>\n    <li>\u5b83\u4ece\u5927\u91cf\u5de5\u4f5c\u573a\u6240\u4f1a\u8bdd\u4e2d\u751f\u6210\u4e86852\u4e2a\u53ef\u91cd\u590d\u7684\u4efb\u52a1\uff0c\u5e76\u9644\u6709\u76f8\u5173\u7684\u4efb\u52a1\u4fe1\u606f\u3002</li>\n    <li>\u7531\u4e8e\u4f1a\u8bdd\u5305\u542b\u4f01\u4e1a\u5185\u90e8\u5185\u5bb9\uff0c\u57fa\u51c6\u6570\u636e\u4e0d\u5bf9\u5916\u53d1\u5e03\uff0c\u4f46\u63d0\u4f9b\u4e86\u6784\u5efa\u548c\u8bc4\u4f30\u534f\u8bae\u3002</li>\n    <li>\u6700\u4f73\u914d\u7f6e\u7684\u5f97\u5206\u4e3a0.663\uff0c\u663e\u793a\u51fa\u8bc4\u4f30\u4f01\u4e1a\u4ee3\u7406\u9700\u8981\u8003\u8651\u591a\u79cd\u56e0\u7d20\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u5355\u4e00\u5206\u6570\u3002</li>\n    <li>\u76f8\u5173\u4ee3\u7801\u53ef\u5728GitHub\u4e0a\u627e\u5230\uff1a<a href=\"https://github.com/FrontisAI/EnterpriseClawBench\">EnterpriseClawBench</a></li>\n</ul>", "summary_simple": "<ul>\n    <li>Enterprise agents work in offices, handling various tasks like reading files and using tools.</li>\n    <li>EnterpriseClawBench is a new benchmark created from real workplace agent sessions, producing 852 tasks with detailed information.</li>\n    <li>The benchmark data isn't publicly available due to internal content, but the methods for creating and testing it are shared.</li>\n    <li>Current top performance on this benchmark is 0.663 with Codex and GPT-5.5, showing that evaluations need to consider multiple factors.</li>\n    <li>Evaluation should include details like model combinations, artifact delivery, visual quality, costs, and runtime, instead of just one score.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.23654.png", "numComments": 1, "submittedBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "fullname": "Kaiyan Zhang", "name": "iseesaw", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.20945", "authors": [{"_id": "6a3a6d28fdcd3514343bb834", "name": "Vishesh Tripathi", "hidden": false}, {"_id": "6a3a6d28fdcd3514343bb835", "name": "Abhay Kumar", "hidden": false}], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "Grouped Query Experts: Mixture-of-Experts on GQA Self-Attention", "submittedOnDailyBy": {"_id": "638828121901766b88076aa1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/rXlOO7eewmmaSN_hQIVz7.jpeg", "isPro": false, "fullname": "Vishesh Tripathi", "user": "vishesh-t27", "type": "user", "name": "vishesh-t27"}, "summary": "Self-attention is central to Transformer performance and is often the most expensive part of the Transformer at long context lengths because its pairwise token interactions scale quadratically with sequence length. Standard dense attention also applies the same set of attention heads to every token regardless of token difficulty or information content. This uniform activation can waste compute, especially as sequences grow longer and attention cost increases rapidly. We propose Grouped Query Experts (GQE), a mixture-of-experts layer on top of grouped-query attention (GQA). Within each GQA group, a router selects k query-head experts per token while all key-value (KV) heads remain dense and unchanged. Thus, GQE keeps the KV cache benefits of GQA and reduces only the active query-head computation. On a fixed 30B token budget at the 250M parameter scale, GQE matches the all-active GQA baseline in downstream accuracy while activating half the query heads per token.", "upvotes": 42, "discussionId": "6a3a6d29fdcd3514343bb836", "ai_summary": "Grouped Query Experts (GQE) improves Transformer efficiency by selectively activating query heads based on token content while maintaining key-value cache benefits of grouped-query attention.", "ai_keywords": ["self-attention", "Transformer", "attention heads", "query-head experts", "grouped-query attention", "mixture-of-experts", "router", "token interactions", "attention cost", "computational efficiency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6968e79166053d81c63a0285", "name": "FrontiersMind", "fullname": "FrontiersMind", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/e2jdcDUMUF0ZD9BGViHuo.png"}, "summary_zh": "<ul>\n    <li>\u81ea\u6ce8\u610f\u529b\u673a\u5236\u662fTransformer\u6027\u80fd\u7684\u5173\u952e\uff0c\u4f46\u5728\u957f\u5e8f\u5217\u4e2d\u8ba1\u7b97\u6210\u672c\u5f88\u9ad8\u3002</li>\n    <li>\u6807\u51c6\u7684\u5bc6\u96c6\u6ce8\u610f\u529b\u5bf9\u6240\u6709\u6807\u8bb0\u4f7f\u7528\u76f8\u540c\u7684\u6ce8\u610f\u529b\u5934\uff0c\u53ef\u80fd\u5bfc\u81f4\u8ba1\u7b97\u8d44\u6e90\u6d6a\u8d39\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u5206\u7ec4\u67e5\u8be2\u4e13\u5bb6\uff08GQE\uff09\uff0c\u8fd9\u662f\u4e00\u79cd\u6df7\u5408\u4e13\u5bb6\u5c42\uff0c\u57fa\u4e8e\u5206\u7ec4\u67e5\u8be2\u6ce8\u610f\u529b\uff08GQA\uff09\u3002</li>\n    <li>\u5728\u6bcf\u4e2aGQA\u7ec4\u4e2d\uff0c\u8def\u7531\u5668\u4e3a\u6bcf\u4e2a\u6807\u8bb0\u9009\u62e9k\u4e2a\u67e5\u8be2\u5934\u4e13\u5bb6\uff0c\u800c\u952e\u503c\u5934\u4fdd\u6301\u4e0d\u53d8\u3002</li>\n    <li>\u5728\u76f8\u540c\u768430\u4ebf\u6807\u8bb0\u9884\u7b97\u4e0b\uff0cGQE\u5728\u4e0b\u6e38\u4efb\u52a1\u4e2d\u4e0e\u5168\u6fc0\u6d3bGQA\u7684\u51c6\u786e\u6027\u76f8\u5f53\uff0c\u4f46\u6bcf\u4e2a\u6807\u8bb0\u53ea\u6fc0\u6d3b\u4e00\u534a\u7684\u67e5\u8be2\u5934\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Self-attention is important for Transformers but can be very costly with long sequences because it processes pairs of tokens in a way that increases with the square of the sequence length.</li>\n  <li>Standard attention uses the same approach for all tokens, which can lead to wasted computing power, especially with longer sequences.</li>\n  <li>The authors introduce a new method called Grouped Query Experts (GQE), which uses a mixture-of-experts approach to improve efficiency.</li>\n  <li>GQE allows a router to choose a smaller number of active query-head experts for each token while keeping other components unchanged.</li>\n  <li>This method achieves similar accuracy to the traditional approach while using only half the query heads for each token, thereby saving computational resources.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "Grouped Query Experts: Mixture-of-Experts on GQA Self-Attention", "summary": "Self-attention is central to Transformer performance and is often the most expensive part of the Transformer at long context lengths because its pairwise token interactions scale quadratically with sequence length. Standard dense attention also applies the same set of attention heads to every token regardless of token difficulty or information content. This uniform activation can waste compute, especially as sequences grow longer and attention cost increases rapidly. We propose Grouped Query Experts (GQE), a mixture-of-experts layer on top of grouped-query attention (GQA). Within each GQA group, a router selects k query-head experts per token while all key-value (KV) heads remain dense and unchanged. Thus, GQE keeps the KV cache benefits of GQA and reduces only the active query-head computation. On a fixed 30B token budget at the 250M parameter scale, GQE matches the all-active GQA baseline in downstream accuracy while activating half the query heads per token.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20945.png", "numComments": 1, "submittedBy": {"_id": "638828121901766b88076aa1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/rXlOO7eewmmaSN_hQIVz7.jpeg", "fullname": "Vishesh Tripathi", "name": "vishesh-t27", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 15, "isUserFollowing": false}, "organization": {"_id": "6968e79166053d81c63a0285", "name": "FrontiersMind", "fullname": "FrontiersMind", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/e2jdcDUMUF0ZD9BGViHuo.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.22807", "authors": [{"_id": "6a39ecbefdcd3514343bb4d0", "user": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "name": "Xinping Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:56.498Z", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d1", "name": "Jiaxin Xu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d2", "name": "Ziqi Dai", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d3", "name": "Xin Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d4", "name": "Shouzheng Huang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d5", "name": "Danyu Tang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d6", "name": "Xinshuo Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d7", "name": "Meishan Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d8", "name": "Baotian Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d9", "name": "Min Zhang", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "submittedOnDailyBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "upvotes": 39, "discussionId": "6a39ecbefdcd3514343bb4da", "projectPage": "https://kalm-embedding.github.io/", "ai_summary": "KaLM-Reranker-V1 is a fast reranker that decouples query and passage computation using encoder-decoder architecture with Matryoshka embedding pooling and cross-attention for efficient relevance modeling.", "ai_keywords": ["reranker", "encoder-decoder architecture", "Matryoshka embedding pooling", "cross-attention", "late-interaction", "parameter-efficient fine-tuning", "BEIR", "MIRACL", "LMEB"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "summary_zh": "<ul>\n    <li>KaLM-Reranker-V1\u662f\u4e00\u79cd\u9ad8\u6548\u7684\u91cd\u6392\u5e8f\u6a21\u578b\uff0c\u80fd\u591f\u72ec\u7acb\u5904\u7406\u67e5\u8be2\u548c\u6bb5\u843d\uff0c\u63d0\u5347\u4e86\u8ba1\u7b97\u6548\u7387\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u7f16\u7801-\u89e3\u7801\u67b6\u6784\uff0c\u4f7f\u7528\u7f16\u7801\u5668\u5bf9\u6bb5\u843d\u8fdb\u884c\u9884\u7f16\u7801\uff0c\u5e76\u901a\u8fc7\u4ea4\u53c9\u6ce8\u610f\u529b\u6355\u6349\u67e5\u8be2\u4e0e\u6bb5\u843d\u4e4b\u95f4\u7684\u76f8\u5173\u6027\u3002</li>\n    <li>KaLM-Reranker-V1\u6709\u4e09\u4e2a\u4e0d\u540c\u7684\u7248\u672c\uff0c\u5206\u522b\u662fNano\u3001Small\u548cLarge\uff0c\u53c2\u6570\u91cf\u4ece0.27B\u52304B\u4e0d\u7b49\u3002</li>\n    <li>\u5728\u591a\u4e2a\u6570\u636e\u96c6\uff08\u5982BEIR\u3001MIRACL\u548cLMEB\uff09\u4e0a\u7684\u5b9e\u9a8c\u8868\u660e\uff0cKaLM-Reranker-V1\u5728\u91cd\u6392\u5e8f\u6027\u80fd\u548c\u6548\u7387\u4e0a\u8868\u73b0\u51fa\u8272\u3002</li>\n    <li>\u7279\u522b\u662f\u5728BEIR\u6570\u636e\u96c6\u4e0a\uff0cKaLM-Reranker-V1\u7684\u6027\u80fd\u4e0e\u5f3a\u5927\u7684\u5de5\u4e1a\u6a21\u578b\u76f8\u5f53\uff0c\u663e\u793a\u51fa\u826f\u597d\u7684\u7ade\u4e89\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>KaLM-Reranker-V1 is a new type of reranking system designed to improve the efficiency of retrieval systems.</li>\n    <li>It separates how queries and passages are processed, which helps maintain flexibility and speed.</li>\n    <li>The system uses an encoder-decoder structure to pre-encode passages and model queries and instructions effectively.</li>\n    <li>KaLM-Reranker-V1 comes in three different sizes: Nano (0.27B parameters), Small (1B), and Large (4B).</li>\n    <li>It shows strong performance in reranking tasks on various benchmarks, even outperforming larger models in some cases.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22807.png", "numComments": 2, "submittedBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "fullname": "Xinping Zhao", "name": "Yuki131", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.20781", "authors": [{"_id": "6a39f61afdcd3514343bb52b", "name": "Qiuhong Shen", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52c", "name": "Shihua Zhang", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52d", "name": "Yue Liao", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52e", "user": {"_id": "6706ab1168e9971e91bad6f7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/tWSXpBEAm0d8gTDWFRxTS.png", "isPro": false, "fullname": "LIQIIIII", "user": "LIQIIIII", "type": "user", "name": "LIQIIIII"}, "name": "Qi Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:48.262Z", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52f", "name": "Zhenxiong Tan", "hidden": false}, {"_id": "6a39f61afdcd3514343bb530", "name": "Shizun Wang", "hidden": false}, {"_id": "6a39f61afdcd3514343bb531", "name": "Shuicheng Yan", "hidden": false}, {"_id": "6a39f61afdcd3514343bb532", "name": "Xinchao Wang", "hidden": false}], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "World Action Models: A Survey", "submittedOnDailyBy": {"_id": "643a6e89a856622f9788bf67", "avatarUrl": "/avatars/419c0379f072295b27d4bfe2f8fb946d.svg", "isPro": false, "fullname": "qiuhong shen", "user": "florinshum", "type": "user", "name": "florinshum"}, "summary": "World Action Models (WAMs) are embodied predictive-action models that make a forecast of the future available to action. Recent WAMs repurpose large video generation models, and a parallel line relies on language or vision-language backbones without a video-generation core. This rapid expansion has blurred the boundary among broad world models, video generation models, action-grounded video world models, Vision-Language-Action policies, and WAMs. This survey gives the field a common account. It first clarifies these boundaries, then organizes existing works through two complementary views. The first view asks what each method is required to generate, spanning rendered futures, latent futures, and video-generation-free action reasoning. The second view decomposes each method by predictive substrate, backbone, action coupling, and deployment regime. This anatomy supports a unified discussion of interactability, causality, persistence, physical plausibility, and generalization, followed by data, evaluation, and open challenges. Across these axes, a consistent design pattern emerges: WAMs are not simply video generators with action heads, but predictive-action methods whose design choices trade representational richness against compute, memory, latency, and action-label cost. The field is moving toward methods that generate less of the future while preserving what control requires. The survey homepage is available at https://world-action-models.github.io/.", "upvotes": 37, "discussionId": "6a39f61bfdcd3514343bb533", "projectPage": "https://world-action-models.github.io/", "githubRepo": "https://github.com/world-action-models/awesome-world-action-models", "githubRepoAddedBy": "user", "ai_summary": "World Action Models are predictive-action systems that generate future states for decision-making, with designs balancing representational richness against computational constraints.", "ai_keywords": ["world action models", "embodied predictive-action models", "video generation models", "vision-language backbones", "predictive substrate", "action coupling", "deployment regime", "interactability", "causality", "physical plausibility", "generalization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 233, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "summary_zh": "<ul>\n    <li>\u4e16\u754c\u884c\u52a8\u6a21\u578b\uff08WAMs\uff09\u662f\u4e00\u79cd\u9884\u6d4b\u6027\u884c\u52a8\u6a21\u578b\uff0c\u53ef\u4ee5\u9884\u6d4b\u672a\u6765\u7684\u884c\u52a8\u3002</li>\n    <li>\u6700\u8fd1\u7684WAMs\u5229\u7528\u5927\u578b\u89c6\u9891\u751f\u6210\u6a21\u578b\uff0c\u5e76\u7ed3\u5408\u8bed\u8a00\u6216\u89c6\u89c9-\u8bed\u8a00\u7684\u57fa\u7840\u3002</li>\n    <li>\u8fd9\u9879\u8c03\u67e5\u65e8\u5728\u660e\u786e\u4e0d\u540c\u6a21\u578b\u4e4b\u95f4\u7684\u754c\u9650\uff0c\u5e76\u5bf9\u73b0\u6709\u5de5\u4f5c\u8fdb\u884c\u5206\u7c7b\u3002</li>\n    <li>\u8c03\u67e5\u63d0\u4f9b\u4e86\u5173\u4e8e\u4ea4\u4e92\u6027\u3001\u56e0\u679c\u5173\u7cfb\u548c\u4e00\u822c\u5316\u7b49\u4e3b\u9898\u7684\u7edf\u4e00\u8ba8\u8bba\u3002</li>\n    <li>WAMs\u7684\u8bbe\u8ba1\u9009\u62e9\u5728\u8868\u73b0\u529b\u548c\u8ba1\u7b97\u3001\u5185\u5b58\u3001\u5ef6\u8fdf\u7b49\u65b9\u9762\u8fdb\u884c\u6743\u8861\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>World Action Models (WAMs) predict future actions and outcomes based on past data.</li>\n    <li>Recent developments in WAMs use large video generation models and language or vision-language models.</li>\n    <li>This survey clarifies the differences between various types of models related to action and video generation.</li>\n    <li>It organizes existing methods based on what they generate and how they predict actions.</li>\n    <li>WAMs aim to balance complexity with efficiency, focusing on generating essential future actions rather than full video outputs.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "World Action Models: A Survey", "summary": "World Action Models (WAMs) are embodied predictive-action models that make a forecast of the future available to action. Recent WAMs repurpose large video generation models, and a parallel line relies on language or vision-language backbones without a video-generation core. This rapid expansion has blurred the boundary among broad world models, video generation models, action-grounded video world models, Vision-Language-Action policies, and WAMs. This survey gives the field a common account. It first clarifies these boundaries, then organizes existing works through two complementary views. The first view asks what each method is required to generate, spanning rendered futures, latent futures, and video-generation-free action reasoning. The second view decomposes each method by predictive substrate, backbone, action coupling, and deployment regime. This anatomy supports a unified discussion of interactability, causality, persistence, physical plausibility, and generalization, followed by data, evaluation, and open challenges. Across these axes, a consistent design pattern emerges: WAMs are not simply video generators with action heads, but predictive-action methods whose design choices trade representational richness against compute, memory, latency, and action-label cost. The field is moving toward methods that generate less of the future while preserving what control requires. The survey homepage is available at https://world-action-models.github.io/.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20781.png", "numComments": 1, "submittedBy": {"_id": "643a6e89a856622f9788bf67", "avatarUrl": "/avatars/419c0379f072295b27d4bfe2f8fb946d.svg", "fullname": "qiuhong shen", "name": "florinshum", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 10, "isUserFollowing": false}, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.22883", "authors": [{"_id": "6a3a09ebfdcd3514343bb61c", "name": "Zhanbo Hua", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61d", "name": "Yifan Yao", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61e", "name": "Weihao Xie", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61f", "name": "Yongchi Zhao", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb620", "user": {"_id": "6417d9ea8f689506e7148417", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6417d9ea8f689506e7148417/bAYcruWNw4WvmuQcGgcwC.jpeg", "isPro": false, "fullname": "minghao", "user": "Liam-Liu", "type": "user", "name": "Liam-Liu"}, "name": "Minghao Liu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:14.672Z", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb621", "name": "Ruizhi Qiu", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb622", "name": "Zhewei Huang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb623", "name": "Zun Wang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb624", "name": "Yiyan Ji", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb625", "name": "Yunhai Ye", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb626", "name": "Letian Zhu", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb627", "name": "Xinping Lei", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb628", "name": "Han Li", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb629", "name": "Zhiyuan Ma", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62a", "name": "Zili Wang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62b", "name": "Zhaoxiang Zhang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62c", "name": "Jiaheng Liu", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "CLI-Universe: Towards Verifiable Task Synthesis Engine for Terminal Agents", "submittedOnDailyBy": {"_id": "65377c30e48353201e6fdda0", "avatarUrl": "/avatars/a8f803b6f2e598eaee9c52c0d2ddfc16.svg", "isPro": false, "fullname": "Jiaheng Liu", "user": "CheeryLJH", "type": "user", "name": "CheeryLJH"}, "summary": "While recent LLM-based terminal agents have demonstrated promising capabilities, the scarcity of high-quality, executable training data remains a critical bottleneck. Existing synthesis pipelines typically scale by retrofitting surface-level artifacts into tasks, frequently yielding ambiguous instructions, shallow execution paths, and brittle tests that provide weak learning signals. To overcome this, we introduce CLI-Universe, a principled synthesis engine that constructs terminal-agent tasks. CLI-Universe generates candidate tasks by sampling combinations across a multi-dimensional capability taxonomy (domain, skill type, capability, and engineering pillar), then grounds each candidate through evidence-guided deep research over real-world technical materials. To ensure rigorous supervision, validated blueprints are instantiated into Dockerized environments and subjected to a multi-stage executable verification pipeline featuring rubric-gated test construction, hint-conditional filtering, and strict fail-to-pass checking. Across the full pipeline, from candidate generation to verification, approximately two-thirds of candidates are discarded, retaining only those that are genuine, verifiable, and non-trivially challenging. To validate our framework, we instantiate a highly distilled dataset of 6,000 trajectories called CLI-Universe-6K. Remarkably, fine-tuning Qwen3-32B on CLI-Universe-6K achieves 33.4% on Terminal-Bench 2.0. This sets a new state-of-the-art for models trained on open-source data at or below 32B parameters, and outperforms several models an order of magnitude larger, demonstrating the profound data efficiency of structured, high-fidelity synthesis.", "upvotes": 27, "discussionId": "6a3a09ebfdcd3514343bb62d", "ai_summary": "A principled synthesis engine generates high-quality terminal-agent tasks through multi-dimensional capability taxonomy and evidence-guided research, creating a distilled dataset that enables significant performance gains in LLM training.", "ai_keywords": ["LLM-based terminal agents", "executable training data", "synthesis engine", "capability taxonomy", "evidence-guided deep research", "Dockerized environments", "executable verification pipeline", "rubric-gated test construction", "fail-to-pass checking", "Terminal-Bench 2.0", "Qwen3-32B", "CLI-Universe-6K"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68edc767abe005ac1b354573", "name": "NJU-LINK", "fullname": "NJU-LINK Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67f9d060395fb1a0d7e4ae21/O3V4UZjcSGnOivcQqTcXW.png"}, "summary_zh": "<ul>\n    <li>\u5f53\u524d\u57fa\u4e8e\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u7684\u7ec8\u7aef\u4ee3\u7406\u9762\u4e34\u9ad8\u8d28\u91cf\u53ef\u6267\u884c\u8bad\u7ec3\u6570\u636e\u4e0d\u8db3\u7684\u95ee\u9898\u3002</li>\n    <li>\u73b0\u6709\u7684\u6570\u636e\u5408\u6210\u6d41\u7a0b\u901a\u5e38\u751f\u6210\u6a21\u7cca\u6307\u4ee4\u548c\u8106\u5f31\u6d4b\u8bd5\uff0c\u5bfc\u81f4\u5b66\u4e60\u4fe1\u53f7\u8f83\u5f31\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86CLI-Universe\uff0c\u4e00\u4e2a\u7cfb\u7edf\u5316\u7684\u5408\u6210\u5f15\u64ce\uff0c\u7528\u4e8e\u6784\u5efa\u7ec8\u7aef\u4ee3\u7406\u4efb\u52a1\u3002</li>\n    <li>CLI-Universe\u901a\u8fc7\u771f\u5b9e\u6280\u672f\u6750\u6599\u7684\u6df1\u5ea6\u7814\u7a76\u751f\u6210\u5019\u9009\u4efb\u52a1\uff0c\u5e76\u5728\u4e25\u683c\u7684\u9a8c\u8bc1\u6d41\u7a0b\u4e2d\u7b5b\u9009\u6709\u6548\u4efb\u52a1\u3002</li>\n    <li>\u901a\u8fc7\u5728CLI-Universe-6K\u6570\u636e\u96c6\u4e0a\u5fae\u8c03Qwen3-32B\u6a21\u578b\uff0c\u8fbe\u5230\u4e86\u65b0\u7684\u6027\u80fd\u6807\u51c6\uff0c\u663e\u793a\u51fa\u9ad8\u6548\u7684\u6570\u636e\u5408\u6210\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current terminal agents using large language models (LLMs) struggle due to a lack of high-quality training data.</li>\n    <li>Existing methods often create unclear instructions and weak tests, leading to poor learning outcomes.</li>\n    <li>CLI-Universe is a new tool that generates better training tasks by combining different capabilities and using real-world resources for validation.</li>\n    <li>It includes a rigorous process to verify tasks, discarding about two-thirds of generated candidates to ensure quality and challenge.</li>\n    <li>Using a refined dataset called CLI-Universe-6K, a model achieved a new record in performance, highlighting the effectiveness of high-quality data synthesis.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "CLI-Universe: Towards Verifiable Task Synthesis Engine for Terminal Agents", "summary": "While recent LLM-based terminal agents have demonstrated promising capabilities, the scarcity of high-quality, executable training data remains a critical bottleneck. Existing synthesis pipelines typically scale by retrofitting surface-level artifacts into tasks, frequently yielding ambiguous instructions, shallow execution paths, and brittle tests that provide weak learning signals. To overcome this, we introduce CLI-Universe, a principled synthesis engine that constructs terminal-agent tasks. CLI-Universe generates candidate tasks by sampling combinations across a multi-dimensional capability taxonomy (domain, skill type, capability, and engineering pillar), then grounds each candidate through evidence-guided deep research over real-world technical materials. To ensure rigorous supervision, validated blueprints are instantiated into Dockerized environments and subjected to a multi-stage executable verification pipeline featuring rubric-gated test construction, hint-conditional filtering, and strict fail-to-pass checking. Across the full pipeline, from candidate generation to verification, approximately two-thirds of candidates are discarded, retaining only those that are genuine, verifiable, and non-trivially challenging. To validate our framework, we instantiate a highly distilled dataset of 6,000 trajectories called CLI-Universe-6K. Remarkably, fine-tuning Qwen3-32B on CLI-Universe-6K achieves 33.4% on Terminal-Bench 2.0. This sets a new state-of-the-art for models trained on open-source data at or below 32B parameters, and outperforms several models an order of magnitude larger, demonstrating the profound data efficiency of structured, high-fidelity synthesis.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22883.png", "numComments": 1, "submittedBy": {"_id": "65377c30e48353201e6fdda0", "avatarUrl": "/avatars/a8f803b6f2e598eaee9c52c0d2ddfc16.svg", "fullname": "Jiaheng Liu", "name": "CheeryLJH", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 29, "isUserFollowing": false}, "organization": {"_id": "68edc767abe005ac1b354573", "name": "NJU-LINK", "fullname": "NJU-LINK Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67f9d060395fb1a0d7e4ae21/O3V4UZjcSGnOivcQqTcXW.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.21649", "authors": [{"_id": "6a39e797fdcd3514343bb4c2", "user": {"_id": "69b14cdeeed94a88011ce095", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/1LRe2njtqTGIsBTkOSIOT.jpeg", "isPro": false, "fullname": "Nie", "user": "ClareNie", "type": "user", "name": "ClareNie"}, "name": "Chang Nie", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:58.268Z", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c3", "name": "Chaoyou Fu", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c4", "name": "Junlan Feng", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c5", "name": "Caifeng Shan", "hidden": false}], "publishedAt": "2026-06-19T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "EvoEmbedding: Evolvable Representations for Long-Context Retrieval and Agentic Memory", "submittedOnDailyBy": {"_id": "653b268cd1041ca9188954da", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/653b268cd1041ca9188954da/5Qy0fyQdRCIUUAzV6fg1k.png", "isPro": false, "fullname": "Chaoyou Fu", "user": "BradyFU", "type": "user", "name": "BradyFU"}, "summary": "Existing embedding models are inherently static: they encode text segments in isolation, ignoring their surrounding context and temporal order. This paper introduces EvoEmbedding, a novel embedding model that generates evolvable representations for retrieval. It is tailored for long-context scenarios, where information is dynamic, sequential, and requires continuous state tracking. Our design is simple: EvoEmbedding maintains a continuously updated latent memory as it sequentially processes inputs, and uses it alongside the raw content to jointly generate evolvable embeddings. Consequently, for the same query, our model adapts its representation to retrieve distinct targets based on the evolving context, going beyond static semantic search. To equip the model with this capability, we construct EvoTrain-180K, a diverse dataset for the joint optimization of latent memory and retrieval. Furthermore, we introduce a memory queue to prevent representation collapse during recurrent encoding, alongside segment-batching techniques that tackle significant length variance and accelerate training by 3.8times. Extensive experiments show that our model not only outperforms larger-scale specialists (e.g., Qwen3-Embedding-8B and KaLM-Embedding-Gemma3-12B) across a range of long-context retrieval benchmarks, but also generalizes well to downstream tasks (e.g., personalization) with contexts 10times longer than its training window. Notably, EvoEmbedding seamlessly integrates into agentic workflows to boost performance. For instance, a naive RAG pipeline equipped with our model surpasses dedicated agentic memory systems. Project Page: https://clare-nie.github.io/EvoEmbedding.", "upvotes": 24, "discussionId": "6a39e798fdcd3514343bb4c6", "projectPage": "https://clare-nie.github.io/EvoEmbedding/", "githubRepo": "https://github.com/MiG-NJU/EvoEmbedding", "githubRepoAddedBy": "user", "ai_summary": "EvoEmbedding is a dynamic embedding model that generates adaptive representations by maintaining a continuously updated latent memory, enabling improved retrieval performance in long-context scenarios.", "ai_keywords": ["evolvable representations", "latent memory", "sequential processing", "joint generation", "representation collapse", "segment-batching", "long-context retrieval", "agentic workflows", "RAG pipeline"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 21, "organization": {"_id": "638f70e8f1256a80d4288555", "name": "nanjinguniv", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638f706ef1256a80d42880f9/6M6-JzwJGiLxjIJzvCflf.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u6709\u7684\u5d4c\u5165\u6a21\u578b\u662f\u9759\u6001\u7684\uff0c\u65e0\u6cd5\u8003\u8651\u6587\u672c\u7684\u4e0a\u4e0b\u6587\u548c\u65f6\u95f4\u987a\u5e8f\u3002</li>\n    <li>EvoEmbedding\u662f\u4e00\u79cd\u65b0\u578b\u5d4c\u5165\u6a21\u578b\uff0c\u80fd\u591f\u751f\u6210\u53ef\u6f14\u53d8\u7684\u8868\u793a\uff0c\u9002\u7528\u4e8e\u957f\u4e0a\u4e0b\u6587\u573a\u666f\u3002</li>\n    <li>\u8be5\u6a21\u578b\u901a\u8fc7\u6301\u7eed\u66f4\u65b0\u7684\u6f5c\u5728\u8bb0\u5fc6\u6765\u5904\u7406\u8f93\u5165\uff0c\u5e76\u4e0e\u539f\u59cb\u5185\u5bb9\u4e00\u8d77\u751f\u6210\u5d4c\u5165\u3002</li>\n    <li>EvoEmbedding\u5728\u68c0\u7d22\u65f6\u80fd\u591f\u6839\u636e\u4e0d\u65ad\u53d8\u5316\u7684\u4e0a\u4e0b\u6587\u8c03\u6574\u8868\u793a\uff0c\u8d85\u8d8a\u4e86\u9759\u6001\u8bed\u4e49\u641c\u7d22\u3002</li>\n    <li>\u6a21\u578b\u5728\u591a\u4e2a\u957f\u4e0a\u4e0b\u6587\u68c0\u7d22\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8d85\u8d8a\u4e86\u66f4\u5927\u89c4\u6a21\u7684\u4e13\u7528\u6a21\u578b\uff0c\u5e76\u80fd\u5f88\u597d\u5730\u9002\u5e94\u4e0b\u6e38\u4efb\u52a1\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>EvoEmbedding is a new model that creates flexible text representations for better information retrieval.</li>\n    <li>It processes information in a sequence, keeping track of context and changes over time.</li>\n    <li>The model updates its memory continuously, allowing it to adapt responses based on evolving situations.</li>\n    <li>EvoEmbedding has been trained on a large dataset and shows improved performance in retrieving long-context information compared to other models.</li>\n    <li>It works well in various applications and can enhance workflows, outperforming traditional memory systems.</li>\n</ul>"}, "publishedAt": "2026-06-18T20:00:00.000Z", "title": "EvoEmbedding: Evolvable Representations for Long-Context Retrieval and Agentic Memory", "summary": "Existing embedding models are inherently static: they encode text segments in isolation, ignoring their surrounding context and temporal order. This paper introduces EvoEmbedding, a novel embedding model that generates evolvable representations for retrieval. It is tailored for long-context scenarios, where information is dynamic, sequential, and requires continuous state tracking. Our design is simple: EvoEmbedding maintains a continuously updated latent memory as it sequentially processes inputs, and uses it alongside the raw content to jointly generate evolvable embeddings. Consequently, for the same query, our model adapts its representation to retrieve distinct targets based on the evolving context, going beyond static semantic search. To equip the model with this capability, we construct EvoTrain-180K, a diverse dataset for the joint optimization of latent memory and retrieval. Furthermore, we introduce a memory queue to prevent representation collapse during recurrent encoding, alongside segment-batching techniques that tackle significant length variance and accelerate training by 3.8times. Extensive experiments show that our model not only outperforms larger-scale specialists (e.g., Qwen3-Embedding-8B and KaLM-Embedding-Gemma3-12B) across a range of long-context retrieval benchmarks, but also generalizes well to downstream tasks (e.g., personalization) with contexts 10times longer than its training window. Notably, EvoEmbedding seamlessly integrates into agentic workflows to boost performance. For instance, a naive RAG pipeline equipped with our model surpasses dedicated agentic memory systems. Project Page: https://clare-nie.github.io/EvoEmbedding.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.21649.png", "numComments": 3, "submittedBy": {"_id": "653b268cd1041ca9188954da", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/653b268cd1041ca9188954da/5Qy0fyQdRCIUUAzV6fg1k.png", "fullname": "Chaoyou Fu", "name": "BradyFU", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 8, "isUserFollowing": false}, "organization": {"_id": "638f70e8f1256a80d4288555", "name": "nanjinguniv", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638f706ef1256a80d42880f9/6M6-JzwJGiLxjIJzvCflf.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.22138", "authors": [{"_id": "6a3a43befdcd3514343bb77d", "name": "Qizhi Pei", "hidden": false}, {"_id": "6a3a43befdcd3514343bb77e", "name": "Zhimeng Zhou", "hidden": false}, {"_id": "6a3a43befdcd3514343bb77f", "name": "Yi Duan", "hidden": false}, {"_id": "6a3a43befdcd3514343bb780", "user": {"_id": "69b908edbef54093046690c2", "avatarUrl": "/avatars/fecd1968ee87947dc997f67b4e4dad1e.svg", "isPro": false, "fullname": "Yann Zhao", "user": "Yann-YYZhao", "type": "user", "name": "Yann-YYZhao"}, "name": "Yiyang Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:55:03.757Z", "hidden": false}, {"_id": "6a3a43befdcd3514343bb781", "name": "Wei Li", "hidden": false}, {"_id": "6a3a43befdcd3514343bb782", "name": "Han Guo", "hidden": false}, {"_id": "6a3a43befdcd3514343bb783", "name": "Liang He", "hidden": false}, {"_id": "6a3a43befdcd3514343bb784", "name": "Chengping Li", "hidden": false}, {"_id": "6a3a43befdcd3514343bb785", "name": "Chang-Yu Hsieh", "hidden": false}, {"_id": "6a3a43befdcd3514343bb786", "name": "Conghui He", "hidden": false}, {"_id": "6a3a43befdcd3514343bb787", "name": "Rui Yan", "hidden": false}, {"_id": "6a3a43befdcd3514343bb788", "name": "Lijun Wu", "hidden": false}], "publishedAt": "2026-06-20T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "BioMatrix: Towards a Comprehensive Biological Foundation Model Spanning the Modality Matrix of Sequences, Structures, and Language", "submittedOnDailyBy": {"_id": "6397f6081323f19c578f142e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6397f6081323f19c578f142e/it7FYYKjlLX8wSsMLm8EO.jpeg", "isPro": false, "fullname": "QizhiPei", "user": "QizhiPei", "type": "user", "name": "QizhiPei"}, "summary": "We present BioMatrix, the first multimodal foundation model that natively integrates sequences, structures, and natural language for both molecules and proteins within a single decoder-only architecture. Existing biological foundation models pursue native multimodality and broad entity coverage separately: those that fuse multiple modalities under a shared objective remain confined to a single entity type, while those spanning multiple entity types either omit explicit structural modeling or rely on adapter-based designs in which the model cannot natively generate the very modalities it can read. BioMatrix closes this gap by mapping molecular sequences (supporting both SMILES and SELFIES notations), molecular structures, protein sequences, protein structures, and natural language into a shared discrete token space through a unified tokenization scheme, so that all modalities are consumed and produced uniformly under a single next-token prediction objective -- without external encoders, projection adapters, or modality-specific output heads. Built upon the Qwen3 language model (1.7B and 4B), BioMatrix is continually pretrained on 304.4 billion tokens spanning general and domain-specific text, sequence and structure views of molecules and proteins, and cross-modal corpora that interleave biomolecular entities with scientific text and link distinct entities through molecule-protein and protein-protein interaction data. After tuning on a comprehensive suite of downstream applications covering 80 tasks across 6 categories -- encompassing single-entity and multi-entity understanding and generation tasks across and within modalities -- BioMatrix achieves state-of-the-art or competitive performance on 77 out of 80 tasks, demonstrating that a single, natively multimodal generalist model can effectively match or surpass specialized approaches across a wide range of biological tasks.", "upvotes": 19, "discussionId": "6a3a43bffdcd3514343bb789", "githubRepo": "https://github.com/QizhiPei/BioMatrix", "githubRepoAddedBy": "user", "ai_summary": "BioMatrix is a novel multimodal foundation model that integrates molecular sequences, structures, and natural language into a unified decoder-only architecture for diverse biological tasks.", "ai_keywords": ["multimodal foundation model", "decoder-only architecture", "next-token prediction", "tokenization scheme", "continual pretraining", "downstream applications", "cross-modal corpora", "molecular sequences", "protein sequences", "molecular structures", "protein structures", "natural language", "unified discrete token space"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 22, "organization": {"_id": "6747ee5decec679eafb90450", "name": "ShanghaiAiLab", "fullname": "shanghai ailab ", "avatar": "https://www.gravatar.com/avatar/6cd2acf412ad103653d9ce14a1aacc19?d=retro&size=100"}, "summary_zh": "<ul>\n    <li>BioMatrix\u662f\u9996\u4e2a\u5c06\u5206\u5b50\u548c\u86cb\u767d\u8d28\u7684\u5e8f\u5217\u3001\u7ed3\u6784\u548c\u81ea\u7136\u8bed\u8a00\u96c6\u6210\u5728\u4e00\u8d77\u7684\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\u3002</li>\n    <li>\u5b83\u4f7f\u7528\u7edf\u4e00\u7684\u6807\u8bb0\u5316\u65b9\u6848\uff0c\u5c06\u4e0d\u540c\u6a21\u6001\uff08\u5982\u5206\u5b50\u5e8f\u5217\u3001\u86cb\u767d\u8d28\u5e8f\u5217\u7b49\uff09\u6620\u5c04\u5230\u5171\u4eab\u7684\u79bb\u6563\u6807\u8bb0\u7a7a\u95f4\u4e2d\u3002</li>\n    <li>BioMatrix\u57283044\u4ebf\u4e2a\u6807\u8bb0\u4e0a\u8fdb\u884c\u6301\u7eed\u9884\u8bad\u7ec3\uff0c\u5305\u62ec\u901a\u7528\u6587\u672c\u548c\u7279\u5b9a\u9886\u57df\u7684\u5e8f\u5217\u548c\u7ed3\u6784\u6570\u636e\u3002</li>\n    <li>\u7ecf\u8fc7\u8c03\u4f18\u540e\uff0cBioMatrix\u572880\u4e2a\u4efb\u52a1\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u8fbe\u5230\u6216\u8d85\u8fc7\u4e8677\u4e2a\u4efb\u52a1\u7684\u6700\u65b0\u6c34\u5e73\u3002</li>\n    <li>\u8fd9\u4e2a\u6a21\u578b\u5c55\u793a\u4e86\u4e00\u4e2a\u5355\u4e00\u7684\u591a\u6a21\u6001\u6a21\u578b\u80fd\u591f\u6709\u6548\u5730\u5904\u7406\u591a\u79cd\u751f\u7269\u4efb\u52a1\uff0c\u8d85\u8d8a\u4e86\u4e13\u95e8\u7684\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>BioMatrix is a new model that combines different types of biological data, like sequences, structures, and natural language, into one system.</li>\n    <li>Unlike other models, BioMatrix can handle multiple entity types without needing extra tools or complicated setups.</li>\n    <li>It uses a unified token system to process and generate various biological data types equally.</li>\n    <li>BioMatrix was trained on a large amount of diverse data, covering many biological topics and tasks.</li>\n    <li>It performs very well on 77 out of 80 tested tasks, showing it can compete with specialized models in biology.</li>\n</ul>"}, "publishedAt": "2026-06-19T20:00:00.000Z", "title": "BioMatrix: Towards a Comprehensive Biological Foundation Model Spanning the Modality Matrix of Sequences, Structures, and Language", "summary": "We present BioMatrix, the first multimodal foundation model that natively integrates sequences, structures, and natural language for both molecules and proteins within a single decoder-only architecture. Existing biological foundation models pursue native multimodality and broad entity coverage separately: those that fuse multiple modalities under a shared objective remain confined to a single entity type, while those spanning multiple entity types either omit explicit structural modeling or rely on adapter-based designs in which the model cannot natively generate the very modalities it can read. BioMatrix closes this gap by mapping molecular sequences (supporting both SMILES and SELFIES notations), molecular structures, protein sequences, protein structures, and natural language into a shared discrete token space through a unified tokenization scheme, so that all modalities are consumed and produced uniformly under a single next-token prediction objective -- without external encoders, projection adapters, or modality-specific output heads. Built upon the Qwen3 language model (1.7B and 4B), BioMatrix is continually pretrained on 304.4 billion tokens spanning general and domain-specific text, sequence and structure views of molecules and proteins, and cross-modal corpora that interleave biomolecular entities with scientific text and link distinct entities through molecule-protein and protein-protein interaction data. After tuning on a comprehensive suite of downstream applications covering 80 tasks across 6 categories -- encompassing single-entity and multi-entity understanding and generation tasks across and within modalities -- BioMatrix achieves state-of-the-art or competitive performance on 77 out of 80 tasks, demonstrating that a single, natively multimodal generalist model can effectively match or surpass specialized approaches across a wide range of biological tasks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22138.png", "numComments": 1, "submittedBy": {"_id": "6397f6081323f19c578f142e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6397f6081323f19c578f142e/it7FYYKjlLX8wSsMLm8EO.jpeg", "fullname": "QizhiPei", "name": "QizhiPei", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 36, "isUserFollowing": false}, "organization": {"_id": "6747ee5decec679eafb90450", "name": "ShanghaiAiLab", "fullname": "shanghai ailab ", "avatar": "https://www.gravatar.com/avatar/6cd2acf412ad103653d9ce14a1aacc19?d=retro&size=100"}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2606.22388", "authors": [{"_id": "6a39f5e9fdcd3514343bb51d", "user": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "isPro": false, "fullname": "Jeff", "user": "JiayuJeff", "type": "user", "name": "JiayuJeff"}, "name": "Jiayu Liu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:50.325Z", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb51e", "name": "Qihan Lin", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb51f", "name": "Cheng Qian", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb520", "name": "Rui Wang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb521", "name": "Emre Can Acikgoz", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb522", "name": "Xiaocheng Yang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb523", "name": "Jiateng Liu", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb524", "name": "Zhenhailong Wang", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb525", "name": "Xiusi Chen", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb526", "name": "Heng Ji", "hidden": false}, {"_id": "6a39f5e9fdcd3514343bb527", "name": "Dilek Hakkani-T\u00fcr", "hidden": false}], "publishedAt": "2026-06-21T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "PlanBench-XL: Evaluating Long-Horizon Planning of LLM Tool-Use Agents in Large-Scale Tool Ecosystems", "submittedOnDailyBy": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "isPro": false, "fullname": "Jeff", "user": "JiayuJeff", "type": "user", "name": "JiayuJeff"}, "summary": "LLM agents increasingly operate in large tool ecosystems, where real-world tasks require discovering relevant tools, inferring implicit sub-goals, and adapting to dynamic environments over long horizons. However, existing benchmarks rarely evaluate planning under retrieval-limited tool visibility. To address this gap, we introduce PlanBench-XL, an interactive benchmark of 327 retail tasks over 1,665 tools that tests whether agents can iteratively retrieve usable tools, invoke them to uncover intermediate evidence for subsequent calls toward the final goal. PlanBench-XL further features an optional blocking mechanism that simulates real-world unpredictability through missing, failing, or distracting tool functions, forcing agents to detect disrupted paths and adapt at runtime. Experiments on ten leading LLMs show that massive-tool planning remains challenging: while GPT-5.4 achieves 51.90% accuracy in block-free settings, it collapses to 11.36% under the most severe blocking condition. Further analysis shows that agents are especially vulnerable when failures lack explicit error signals or when recovery requires longer alternative tool-use paths. These results establish PlanBench-XL as a testbed for diagnosing agentic planning failures and highlight the need for robust adaptive planning in long-horizon tasks with large, imperfect tool environments.", "upvotes": 79, "discussionId": "6a39f5eafdcd3514343bb528", "projectPage": "https://planbench-xl.github.io/", "githubRepo": "https://github.com/JiayuJeff/PlanBench-XL", "githubRepoAddedBy": "user", "ai_summary": "PlanBench-XL evaluates large language model agents' ability to plan and adapt in complex tool-rich environments with limited visibility and dynamic disruptions.", "ai_keywords": ["LLM agents", "tool ecosystems", "planning", "retrieval-limited tool visibility", "interactive benchmark", "tool discovery", "implicit sub-goals", "dynamic environments", "long horizons", "blocking mechanism", "agent adaptation", "tool-use paths", "agentic planning", "robust planning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 26, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86PlanBench-XL\uff0c\u8fd9\u662f\u4e00\u4e2a\u5305\u542b327\u4e2a\u96f6\u552e\u4efb\u52a1\u548c1,665\u4e2a\u5de5\u5177\u7684\u4e92\u52a8\u57fa\u51c6\u6d4b\u8bd5\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u6d4b\u8bd5\u8bc4\u4f30\u4ee3\u7406\u5728\u6709\u9650\u5de5\u5177\u53ef\u89c1\u6027\u4e0b\u7684\u89c4\u5212\u80fd\u529b\uff0c\u662f\u5426\u80fd\u6709\u6548\u67e5\u627e\u548c\u4f7f\u7528\u5de5\u5177\u3002</li>\n    <li>PlanBench-XL\u6a21\u62df\u73b0\u5b9e\u4e16\u754c\u7684\u4e0d\u786e\u5b9a\u6027\uff0c\u4f8b\u5982\u5de5\u5177\u529f\u80fd\u7f3a\u5931\u6216\u5931\u8d25\uff0c\u8981\u6c42\u4ee3\u7406\u5728\u8fd0\u884c\u65f6\u9002\u5e94\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5c3d\u7ba1GPT-5.4\u5728\u6ca1\u6709\u963b\u585e\u7684\u60c5\u51b5\u4e0b\u670951.90%\u7684\u51c6\u786e\u7387\uff0c\u4f46\u5728\u6700\u4e25\u91cd\u7684\u963b\u585e\u6761\u4ef6\u4e0b\u51c6\u786e\u7387\u964d\u81f311.36%\u3002</li>\n    <li>\u7ed3\u679c\u8868\u660e\uff0c\u4ee3\u7406\u5728\u9762\u5bf9\u7f3a\u4e4f\u660e\u786e\u9519\u8bef\u4fe1\u53f7\u7684\u5931\u8d25\u65f6\uff0c\u5bb9\u6613\u53d7\u5230\u5f71\u54cd\uff0c\u5f3a\u8c03\u4e86\u5728\u5927\u578b\u4e0d\u5b8c\u7f8e\u5de5\u5177\u73af\u5883\u4e2d\u8fdb\u884c\u7a33\u5065\u9002\u5e94\u6027\u89c4\u5212\u7684\u5fc5\u8981\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>PlanBench-XL is a new benchmark designed to test LLM agents on 327 retail tasks using 1,665 tools.</li>\n    <li>It evaluates how well agents can find and use tools, adapt to changing situations, and handle unexpected problems.</li>\n    <li>The benchmark includes a feature that simulates real-world challenges, such as tools failing or not working as expected.</li>\n    <li>Experiments show that even advanced models like GPT-5.4 struggle with planning when faced with tool disruptions.</li>\n    <li>The findings highlight the need for better adaptive planning in complex environments with many tools.</li>\n</ul>"}, "publishedAt": "2026-06-20T20:00:00.000Z", "title": "PlanBench-XL: Evaluating Long-Horizon Planning of LLM Tool-Use Agents in Large-Scale Tool Ecosystems", "summary": "LLM agents increasingly operate in large tool ecosystems, where real-world tasks require discovering relevant tools, inferring implicit sub-goals, and adapting to dynamic environments over long horizons. However, existing benchmarks rarely evaluate planning under retrieval-limited tool visibility. To address this gap, we introduce PlanBench-XL, an interactive benchmark of 327 retail tasks over 1,665 tools that tests whether agents can iteratively retrieve usable tools, invoke them to uncover intermediate evidence for subsequent calls toward the final goal. PlanBench-XL further features an optional blocking mechanism that simulates real-world unpredictability through missing, failing, or distracting tool functions, forcing agents to detect disrupted paths and adapt at runtime. Experiments on ten leading LLMs show that massive-tool planning remains challenging: while GPT-5.4 achieves 51.90% accuracy in block-free settings, it collapses to 11.36% under the most severe blocking condition. Further analysis shows that agents are especially vulnerable when failures lack explicit error signals or when recovery requires longer alternative tool-use paths. These results establish PlanBench-XL as a testbed for diagnosing agentic planning failures and highlight the need for robust adaptive planning in long-horizon tasks with large, imperfect tool environments.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22388.png", "numComments": 3, "submittedBy": {"_id": "66783baec3f824dde8f783ac", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66783baec3f824dde8f783ac/oqFYUrgs2vnGRhAMSrQpC.jpeg", "fullname": "Jeff", "name": "JiayuJeff", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.21337", "authors": [{"_id": "6a3a16b3fdcd3514343bb6a3", "user": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "isPro": false, "fullname": "Cong", "user": "Coneonewan", "type": "user", "name": "Coneonewan"}, "name": "Cong Wan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:05.018Z", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a4", "name": "Zeyu Guo", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a5", "name": "Zijian Cai", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a6", "name": "Jiangyang Li", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a7", "name": "SongLin Dong", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a8", "name": "Lin Peng", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6a9", "user": {"_id": "668df98de9e585e8718f767f", "avatarUrl": "/avatars/2be52f4ae88a0991c8ae584f8e870734.svg", "isPro": false, "fullname": "Xiangyang Luo", "user": "XiangyangLuo02", "type": "user", "name": "XiangyangLuo02"}, "name": "Xiangyang Luo", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:01.079Z", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6aa", "name": "Zhiheng Ma", "hidden": false}, {"_id": "6a3a16b3fdcd3514343bb6ab", "name": "Yihong Gong", "hidden": false}], "publishedAt": "2026-06-19T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "DataClaw0: Agentic Tailoring Multimodal Data from Raw Streams", "submittedOnDailyBy": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "isPro": false, "fullname": "Cong", "user": "Coneonewan", "type": "user", "name": "Coneonewan"}, "summary": "Massive unstructured multimodal streams suffer from high \"data entropy,\" impeding both efficient human knowledge acquisition and high-quality AI post-training. Existing passive annotation paradigms, heavily reliant on heuristic rules or general VLMs, are costly, monotonous, and fail to unlock the deep procedural logic embedded in raw data. We elevate data processing to a learnable capability, proposing a paradigm shift towards Agentic Data Tailoring, which actively refining and structuring data to align with diverse user and downstream intents. To overcome the data scarcity bottleneck in training such high-order capabilities, we design a two-stage pipeline grounding generative semantic synthesis in deterministic Factual Anchors, yielding a large-scale dataset spanning five core physical and digital domains. Building upon this, DataClaw_0-9B model synergizes Supervised Fine-Tuning (SFT) with Group Relative Policy Optimization (GRPO), achieving robust alignment with complex refinement and tailoring intents. To systematically quantify this capability, we construct DataClaw_0-val, the first benchmark dedicated to data refinement. Crucially, we adopt downstream post-training as the ultimate validation touchstone. Evaluations on video generation, real-world VQA, and GUI navigation confirm that DataClaw_0 delivers high-information-density tailored data, facilitating efficient model adaptation to new tasks under limited training data regimes. Project page: https://czjdsg.github.io/MakeAnyData", "upvotes": 65, "discussionId": "6a3a16b3fdcd3514343bb6ac", "projectPage": "https://czjdsg.github.io/MakeAnyData/#cases", "githubRepo": "https://github.com/vancyland/DataClaw0", "githubRepoAddedBy": "user", "ai_summary": "Agentic Data Tailoring paradigm uses learnable data processing to structure high-entropy multimodal streams, with DataClaw_0-9B model achieving robust alignment through SFT and GRPO on a novel benchmark.", "ai_keywords": ["Agentic Data Tailoring", "generative semantic synthesis", "deterministic Factual Anchors", "Supervised Fine-Tuning", "Group Relative Policy Optimization", "data refinement", "multimodal streams", "data entropy", "downstream post-training"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 24, "summary_zh": "<ul>\n    <li>\u5927\u91cf\u975e\u7ed3\u6784\u5316\u7684\u591a\u6a21\u6001\u6570\u636e\u5b58\u5728\u9ad8\u201c\u6570\u636e\u71b5\u201d\uff0c\u5f71\u54cd\u4eba\u7c7b\u77e5\u8bc6\u83b7\u53d6\u548cAI\u540e\u7eed\u8bad\u7ec3\u7684\u8d28\u91cf\u3002</li>\n    <li>\u73b0\u6709\u7684\u88ab\u52a8\u6ce8\u91ca\u65b9\u6cd5\u4f9d\u8d56\u542f\u53d1\u5f0f\u89c4\u5219\u6216\u901a\u7528\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff0c\u6210\u672c\u9ad8\u4e14\u6548\u7387\u4f4e\uff0c\u65e0\u6cd5\u6df1\u5165\u7406\u89e3\u539f\u59cb\u6570\u636e\u4e2d\u7684\u903b\u8f91\u3002</li>\n    <li>\u63d0\u51fa\u201c\u4e3b\u52a8\u6570\u636e\u5b9a\u5236\u201d\u7684\u65b0\u65b9\u6cd5\uff0c\u901a\u8fc7\u4e3b\u52a8\u6574\u7406\u6570\u636e\u6765\u6ee1\u8db3\u7528\u6237\u548c\u4e0b\u6e38\u9700\u6c42\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u4e00\u4e2a\u4e24\u9636\u6bb5\u6d41\u7a0b\uff0c\u5229\u7528\u786e\u5b9a\u6027\u4e8b\u5b9e\u951a\u70b9\u751f\u6210\u5927\u89c4\u6a21\u6570\u636e\u96c6\uff0c\u6db5\u76d6\u4e94\u4e2a\u6838\u5fc3\u9886\u57df\u3002</li>\n    <li>DataClaw_0-9B\u6a21\u578b\u7ed3\u5408\u76d1\u7763\u5fae\u8c03\u548c\u7ec4\u76f8\u5bf9\u7b56\u7565\u4f18\u5316\uff0c\u80fd\u6709\u6548\u652f\u6301\u590d\u6742\u6570\u636e\u7684\u7cbe\u7ec6\u5316\u548c\u5b9a\u5236\u4efb\u52a1\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Unstructured data has high \"data entropy,\" making it hard for humans and AI to learn from it effectively.</li>\n    <li>Current data annotation methods are expensive and don't fully utilize the information in raw data.</li>\n    <li>We propose a new method called Agentic Data Tailoring that actively organizes data to meet different user needs.</li>\n    <li>We created a two-stage process to generate a large dataset that helps train advanced data processing models.</li>\n    <li>The DataClaw_0-9B model improves how AI can adapt to new tasks using tailored data, as shown in various evaluations.</li>\n</ul>"}, "publishedAt": "2026-06-18T20:00:00.000Z", "title": "DataClaw0: Agentic Tailoring Multimodal Data from Raw Streams", "summary": "Massive unstructured multimodal streams suffer from high \"data entropy,\" impeding both efficient human knowledge acquisition and high-quality AI post-training. Existing passive annotation paradigms, heavily reliant on heuristic rules or general VLMs, are costly, monotonous, and fail to unlock the deep procedural logic embedded in raw data. We elevate data processing to a learnable capability, proposing a paradigm shift towards Agentic Data Tailoring, which actively refining and structuring data to align with diverse user and downstream intents. To overcome the data scarcity bottleneck in training such high-order capabilities, we design a two-stage pipeline grounding generative semantic synthesis in deterministic Factual Anchors, yielding a large-scale dataset spanning five core physical and digital domains. Building upon this, DataClaw_0-9B model synergizes Supervised Fine-Tuning (SFT) with Group Relative Policy Optimization (GRPO), achieving robust alignment with complex refinement and tailoring intents. To systematically quantify this capability, we construct DataClaw_0-val, the first benchmark dedicated to data refinement. Crucially, we adopt downstream post-training as the ultimate validation touchstone. Evaluations on video generation, real-world VQA, and GUI navigation confirm that DataClaw_0 delivers high-information-density tailored data, facilitating efficient model adaptation to new tasks under limited training data regimes. Project page: https://czjdsg.github.io/MakeAnyData", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.21337.png", "numComments": 1, "submittedBy": {"_id": "66d7e9519b7da501cd2ceeaa", "avatarUrl": "/avatars/f23c207ef9264851a4cdefb000b22fc4.svg", "fullname": "Cong", "name": "Coneonewan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.23654", "authors": [{"_id": "6a3a0213fdcd3514343bb586", "name": "Jincheng Zhong", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb587", "name": "Weizhi Wang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb588", "name": "Che Jiang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb589", "name": "Kai Tian", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58a", "name": "Zhenzhao Yuan", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58b", "name": "Junlin Yang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58c", "name": "Dianqiao Lei", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58d", "user": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "name": "Kaiyan Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:30.920Z", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "submittedOnDailyBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "upvotes": 57, "discussionId": "6a3a0213fdcd3514343bb58e", "projectPage": "https://frontisai.github.io/EnterpriseClawBench/", "githubRepo": "https://github.com/FrontisAI/EnterpriseClawBench", "githubRepoAddedBy": "user", "ai_summary": "EnterpriseClawBench presents a benchmark for enterprise agents based on real-world sessions with 852 reproducible tasks, emphasizing comprehensive evaluation metrics beyond single performance scores.", "ai_keywords": ["enterprise agent benchmark", "reproducible tasks", "workplace sessions", "harness--model combinations", "artifact delivery", "skill-transfer behavior"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 28, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "summary_zh": "<ul>\n    <li>EnterpriseClawBench\u662f\u4e00\u4e2a\u7528\u4e8e\u4f01\u4e1a\u4ee3\u7406\u7684\u57fa\u51c6\u6d4b\u8bd5\uff0c\u57fa\u4e8e\u771f\u5b9e\u7684\u5de5\u4f5c\u573a\u6240\u4f1a\u8bdd\u6784\u5efa\u3002</li>\n    <li>\u5b83\u4ece\u5927\u91cf\u5de5\u4f5c\u573a\u6240\u4f1a\u8bdd\u4e2d\u751f\u6210\u4e86852\u4e2a\u53ef\u91cd\u590d\u7684\u4efb\u52a1\uff0c\u5e76\u9644\u6709\u76f8\u5173\u7684\u4efb\u52a1\u4fe1\u606f\u3002</li>\n    <li>\u7531\u4e8e\u4f1a\u8bdd\u5305\u542b\u4f01\u4e1a\u5185\u90e8\u5185\u5bb9\uff0c\u57fa\u51c6\u6570\u636e\u4e0d\u5bf9\u5916\u53d1\u5e03\uff0c\u4f46\u63d0\u4f9b\u4e86\u6784\u5efa\u548c\u8bc4\u4f30\u534f\u8bae\u3002</li>\n    <li>\u6700\u4f73\u914d\u7f6e\u7684\u5f97\u5206\u4e3a0.663\uff0c\u663e\u793a\u51fa\u8bc4\u4f30\u4f01\u4e1a\u4ee3\u7406\u9700\u8981\u8003\u8651\u591a\u79cd\u56e0\u7d20\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u5355\u4e00\u5206\u6570\u3002</li>\n    <li>\u76f8\u5173\u4ee3\u7801\u53ef\u5728GitHub\u4e0a\u627e\u5230\uff1a<a href=\"https://github.com/FrontisAI/EnterpriseClawBench\">EnterpriseClawBench</a></li>\n</ul>", "summary_simple": "<ul>\n    <li>Enterprise agents work in offices, handling various tasks like reading files and using tools.</li>\n    <li>EnterpriseClawBench is a new benchmark created from real workplace agent sessions, producing 852 tasks with detailed information.</li>\n    <li>The benchmark data isn't publicly available due to internal content, but the methods for creating and testing it are shared.</li>\n    <li>Current top performance on this benchmark is 0.663 with Codex and GPT-5.5, showing that evaluations need to consider multiple factors.</li>\n    <li>Evaluation should include details like model combinations, artifact delivery, visual quality, costs, and runtime, instead of just one score.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.23654.png", "numComments": 1, "submittedBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "fullname": "Kaiyan Zhang", "name": "iseesaw", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.20945", "authors": [{"_id": "6a3a6d28fdcd3514343bb834", "name": "Vishesh Tripathi", "hidden": false}, {"_id": "6a3a6d28fdcd3514343bb835", "name": "Abhay Kumar", "hidden": false}], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "Grouped Query Experts: Mixture-of-Experts on GQA Self-Attention", "submittedOnDailyBy": {"_id": "638828121901766b88076aa1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/rXlOO7eewmmaSN_hQIVz7.jpeg", "isPro": false, "fullname": "Vishesh Tripathi", "user": "vishesh-t27", "type": "user", "name": "vishesh-t27"}, "summary": "Self-attention is central to Transformer performance and is often the most expensive part of the Transformer at long context lengths because its pairwise token interactions scale quadratically with sequence length. Standard dense attention also applies the same set of attention heads to every token regardless of token difficulty or information content. This uniform activation can waste compute, especially as sequences grow longer and attention cost increases rapidly. We propose Grouped Query Experts (GQE), a mixture-of-experts layer on top of grouped-query attention (GQA). Within each GQA group, a router selects k query-head experts per token while all key-value (KV) heads remain dense and unchanged. Thus, GQE keeps the KV cache benefits of GQA and reduces only the active query-head computation. On a fixed 30B token budget at the 250M parameter scale, GQE matches the all-active GQA baseline in downstream accuracy while activating half the query heads per token.", "upvotes": 42, "discussionId": "6a3a6d29fdcd3514343bb836", "ai_summary": "Grouped Query Experts (GQE) improves Transformer efficiency by selectively activating query heads based on token content while maintaining key-value cache benefits of grouped-query attention.", "ai_keywords": ["self-attention", "Transformer", "attention heads", "query-head experts", "grouped-query attention", "mixture-of-experts", "router", "token interactions", "attention cost", "computational efficiency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6968e79166053d81c63a0285", "name": "FrontiersMind", "fullname": "FrontiersMind", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/e2jdcDUMUF0ZD9BGViHuo.png"}, "summary_zh": "<ul>\n    <li>\u81ea\u6ce8\u610f\u529b\u673a\u5236\u662fTransformer\u6027\u80fd\u7684\u5173\u952e\uff0c\u4f46\u5728\u957f\u5e8f\u5217\u4e2d\u8ba1\u7b97\u6210\u672c\u5f88\u9ad8\u3002</li>\n    <li>\u6807\u51c6\u7684\u5bc6\u96c6\u6ce8\u610f\u529b\u5bf9\u6240\u6709\u6807\u8bb0\u4f7f\u7528\u76f8\u540c\u7684\u6ce8\u610f\u529b\u5934\uff0c\u53ef\u80fd\u5bfc\u81f4\u8ba1\u7b97\u8d44\u6e90\u6d6a\u8d39\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u5206\u7ec4\u67e5\u8be2\u4e13\u5bb6\uff08GQE\uff09\uff0c\u8fd9\u662f\u4e00\u79cd\u6df7\u5408\u4e13\u5bb6\u5c42\uff0c\u57fa\u4e8e\u5206\u7ec4\u67e5\u8be2\u6ce8\u610f\u529b\uff08GQA\uff09\u3002</li>\n    <li>\u5728\u6bcf\u4e2aGQA\u7ec4\u4e2d\uff0c\u8def\u7531\u5668\u4e3a\u6bcf\u4e2a\u6807\u8bb0\u9009\u62e9k\u4e2a\u67e5\u8be2\u5934\u4e13\u5bb6\uff0c\u800c\u952e\u503c\u5934\u4fdd\u6301\u4e0d\u53d8\u3002</li>\n    <li>\u5728\u76f8\u540c\u768430\u4ebf\u6807\u8bb0\u9884\u7b97\u4e0b\uff0cGQE\u5728\u4e0b\u6e38\u4efb\u52a1\u4e2d\u4e0e\u5168\u6fc0\u6d3bGQA\u7684\u51c6\u786e\u6027\u76f8\u5f53\uff0c\u4f46\u6bcf\u4e2a\u6807\u8bb0\u53ea\u6fc0\u6d3b\u4e00\u534a\u7684\u67e5\u8be2\u5934\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Self-attention is important for Transformers but can be very costly with long sequences because it processes pairs of tokens in a way that increases with the square of the sequence length.</li>\n  <li>Standard attention uses the same approach for all tokens, which can lead to wasted computing power, especially with longer sequences.</li>\n  <li>The authors introduce a new method called Grouped Query Experts (GQE), which uses a mixture-of-experts approach to improve efficiency.</li>\n  <li>GQE allows a router to choose a smaller number of active query-head experts for each token while keeping other components unchanged.</li>\n  <li>This method achieves similar accuracy to the traditional approach while using only half the query heads for each token, thereby saving computational resources.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "Grouped Query Experts: Mixture-of-Experts on GQA Self-Attention", "summary": "Self-attention is central to Transformer performance and is often the most expensive part of the Transformer at long context lengths because its pairwise token interactions scale quadratically with sequence length. Standard dense attention also applies the same set of attention heads to every token regardless of token difficulty or information content. This uniform activation can waste compute, especially as sequences grow longer and attention cost increases rapidly. We propose Grouped Query Experts (GQE), a mixture-of-experts layer on top of grouped-query attention (GQA). Within each GQA group, a router selects k query-head experts per token while all key-value (KV) heads remain dense and unchanged. Thus, GQE keeps the KV cache benefits of GQA and reduces only the active query-head computation. On a fixed 30B token budget at the 250M parameter scale, GQE matches the all-active GQA baseline in downstream accuracy while activating half the query heads per token.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20945.png", "numComments": 1, "submittedBy": {"_id": "638828121901766b88076aa1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/rXlOO7eewmmaSN_hQIVz7.jpeg", "fullname": "Vishesh Tripathi", "name": "vishesh-t27", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 15, "isUserFollowing": false}, "organization": {"_id": "6968e79166053d81c63a0285", "name": "FrontiersMind", "fullname": "FrontiersMind", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638828121901766b88076aa1/e2jdcDUMUF0ZD9BGViHuo.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.22807", "authors": [{"_id": "6a39ecbefdcd3514343bb4d0", "user": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "name": "Xinping Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:56.498Z", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d1", "name": "Jiaxin Xu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d2", "name": "Ziqi Dai", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d3", "name": "Xin Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d4", "name": "Shouzheng Huang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d5", "name": "Danyu Tang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d6", "name": "Xinshuo Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d7", "name": "Meishan Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d8", "name": "Baotian Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d9", "name": "Min Zhang", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "submittedOnDailyBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "upvotes": 39, "discussionId": "6a39ecbefdcd3514343bb4da", "projectPage": "https://kalm-embedding.github.io/", "ai_summary": "KaLM-Reranker-V1 is a fast reranker that decouples query and passage computation using encoder-decoder architecture with Matryoshka embedding pooling and cross-attention for efficient relevance modeling.", "ai_keywords": ["reranker", "encoder-decoder architecture", "Matryoshka embedding pooling", "cross-attention", "late-interaction", "parameter-efficient fine-tuning", "BEIR", "MIRACL", "LMEB"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "summary_zh": "<ul>\n    <li>KaLM-Reranker-V1\u662f\u4e00\u79cd\u9ad8\u6548\u7684\u91cd\u6392\u5e8f\u6a21\u578b\uff0c\u80fd\u591f\u72ec\u7acb\u5904\u7406\u67e5\u8be2\u548c\u6bb5\u843d\uff0c\u63d0\u5347\u4e86\u8ba1\u7b97\u6548\u7387\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u7f16\u7801-\u89e3\u7801\u67b6\u6784\uff0c\u4f7f\u7528\u7f16\u7801\u5668\u5bf9\u6bb5\u843d\u8fdb\u884c\u9884\u7f16\u7801\uff0c\u5e76\u901a\u8fc7\u4ea4\u53c9\u6ce8\u610f\u529b\u6355\u6349\u67e5\u8be2\u4e0e\u6bb5\u843d\u4e4b\u95f4\u7684\u76f8\u5173\u6027\u3002</li>\n    <li>KaLM-Reranker-V1\u6709\u4e09\u4e2a\u4e0d\u540c\u7684\u7248\u672c\uff0c\u5206\u522b\u662fNano\u3001Small\u548cLarge\uff0c\u53c2\u6570\u91cf\u4ece0.27B\u52304B\u4e0d\u7b49\u3002</li>\n    <li>\u5728\u591a\u4e2a\u6570\u636e\u96c6\uff08\u5982BEIR\u3001MIRACL\u548cLMEB\uff09\u4e0a\u7684\u5b9e\u9a8c\u8868\u660e\uff0cKaLM-Reranker-V1\u5728\u91cd\u6392\u5e8f\u6027\u80fd\u548c\u6548\u7387\u4e0a\u8868\u73b0\u51fa\u8272\u3002</li>\n    <li>\u7279\u522b\u662f\u5728BEIR\u6570\u636e\u96c6\u4e0a\uff0cKaLM-Reranker-V1\u7684\u6027\u80fd\u4e0e\u5f3a\u5927\u7684\u5de5\u4e1a\u6a21\u578b\u76f8\u5f53\uff0c\u663e\u793a\u51fa\u826f\u597d\u7684\u7ade\u4e89\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>KaLM-Reranker-V1 is a new type of reranking system designed to improve the efficiency of retrieval systems.</li>\n    <li>It separates how queries and passages are processed, which helps maintain flexibility and speed.</li>\n    <li>The system uses an encoder-decoder structure to pre-encode passages and model queries and instructions effectively.</li>\n    <li>KaLM-Reranker-V1 comes in three different sizes: Nano (0.27B parameters), Small (1B), and Large (4B).</li>\n    <li>It shows strong performance in reranking tasks on various benchmarks, even outperforming larger models in some cases.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22807.png", "numComments": 2, "submittedBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "fullname": "Xinping Zhao", "name": "Yuki131", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.20781", "authors": [{"_id": "6a39f61afdcd3514343bb52b", "name": "Qiuhong Shen", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52c", "name": "Shihua Zhang", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52d", "name": "Yue Liao", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52e", "user": {"_id": "6706ab1168e9971e91bad6f7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/tWSXpBEAm0d8gTDWFRxTS.png", "isPro": false, "fullname": "LIQIIIII", "user": "LIQIIIII", "type": "user", "name": "LIQIIIII"}, "name": "Qi Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:48.262Z", "hidden": false}, {"_id": "6a39f61afdcd3514343bb52f", "name": "Zhenxiong Tan", "hidden": false}, {"_id": "6a39f61afdcd3514343bb530", "name": "Shizun Wang", "hidden": false}, {"_id": "6a39f61afdcd3514343bb531", "name": "Shuicheng Yan", "hidden": false}, {"_id": "6a39f61afdcd3514343bb532", "name": "Xinchao Wang", "hidden": false}], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "World Action Models: A Survey", "submittedOnDailyBy": {"_id": "643a6e89a856622f9788bf67", "avatarUrl": "/avatars/419c0379f072295b27d4bfe2f8fb946d.svg", "isPro": false, "fullname": "qiuhong shen", "user": "florinshum", "type": "user", "name": "florinshum"}, "summary": "World Action Models (WAMs) are embodied predictive-action models that make a forecast of the future available to action. Recent WAMs repurpose large video generation models, and a parallel line relies on language or vision-language backbones without a video-generation core. This rapid expansion has blurred the boundary among broad world models, video generation models, action-grounded video world models, Vision-Language-Action policies, and WAMs. This survey gives the field a common account. It first clarifies these boundaries, then organizes existing works through two complementary views. The first view asks what each method is required to generate, spanning rendered futures, latent futures, and video-generation-free action reasoning. The second view decomposes each method by predictive substrate, backbone, action coupling, and deployment regime. This anatomy supports a unified discussion of interactability, causality, persistence, physical plausibility, and generalization, followed by data, evaluation, and open challenges. Across these axes, a consistent design pattern emerges: WAMs are not simply video generators with action heads, but predictive-action methods whose design choices trade representational richness against compute, memory, latency, and action-label cost. The field is moving toward methods that generate less of the future while preserving what control requires. The survey homepage is available at https://world-action-models.github.io/.", "upvotes": 37, "discussionId": "6a39f61bfdcd3514343bb533", "projectPage": "https://world-action-models.github.io/", "githubRepo": "https://github.com/world-action-models/awesome-world-action-models", "githubRepoAddedBy": "user", "ai_summary": "World Action Models are predictive-action systems that generate future states for decision-making, with designs balancing representational richness against computational constraints.", "ai_keywords": ["world action models", "embodied predictive-action models", "video generation models", "vision-language backbones", "predictive substrate", "action coupling", "deployment regime", "interactability", "causality", "physical plausibility", "generalization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 233, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "summary_zh": "<ul>\n    <li>\u4e16\u754c\u884c\u52a8\u6a21\u578b\uff08WAMs\uff09\u662f\u4e00\u79cd\u9884\u6d4b\u6027\u884c\u52a8\u6a21\u578b\uff0c\u53ef\u4ee5\u9884\u6d4b\u672a\u6765\u7684\u884c\u52a8\u3002</li>\n    <li>\u6700\u8fd1\u7684WAMs\u5229\u7528\u5927\u578b\u89c6\u9891\u751f\u6210\u6a21\u578b\uff0c\u5e76\u7ed3\u5408\u8bed\u8a00\u6216\u89c6\u89c9-\u8bed\u8a00\u7684\u57fa\u7840\u3002</li>\n    <li>\u8fd9\u9879\u8c03\u67e5\u65e8\u5728\u660e\u786e\u4e0d\u540c\u6a21\u578b\u4e4b\u95f4\u7684\u754c\u9650\uff0c\u5e76\u5bf9\u73b0\u6709\u5de5\u4f5c\u8fdb\u884c\u5206\u7c7b\u3002</li>\n    <li>\u8c03\u67e5\u63d0\u4f9b\u4e86\u5173\u4e8e\u4ea4\u4e92\u6027\u3001\u56e0\u679c\u5173\u7cfb\u548c\u4e00\u822c\u5316\u7b49\u4e3b\u9898\u7684\u7edf\u4e00\u8ba8\u8bba\u3002</li>\n    <li>WAMs\u7684\u8bbe\u8ba1\u9009\u62e9\u5728\u8868\u73b0\u529b\u548c\u8ba1\u7b97\u3001\u5185\u5b58\u3001\u5ef6\u8fdf\u7b49\u65b9\u9762\u8fdb\u884c\u6743\u8861\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>World Action Models (WAMs) predict future actions and outcomes based on past data.</li>\n    <li>Recent developments in WAMs use large video generation models and language or vision-language models.</li>\n    <li>This survey clarifies the differences between various types of models related to action and video generation.</li>\n    <li>It organizes existing methods based on what they generate and how they predict actions.</li>\n    <li>WAMs aim to balance complexity with efficiency, focusing on generating essential future actions rather than full video outputs.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "World Action Models: A Survey", "summary": "World Action Models (WAMs) are embodied predictive-action models that make a forecast of the future available to action. Recent WAMs repurpose large video generation models, and a parallel line relies on language or vision-language backbones without a video-generation core. This rapid expansion has blurred the boundary among broad world models, video generation models, action-grounded video world models, Vision-Language-Action policies, and WAMs. This survey gives the field a common account. It first clarifies these boundaries, then organizes existing works through two complementary views. The first view asks what each method is required to generate, spanning rendered futures, latent futures, and video-generation-free action reasoning. The second view decomposes each method by predictive substrate, backbone, action coupling, and deployment regime. This anatomy supports a unified discussion of interactability, causality, persistence, physical plausibility, and generalization, followed by data, evaluation, and open challenges. Across these axes, a consistent design pattern emerges: WAMs are not simply video generators with action heads, but predictive-action methods whose design choices trade representational richness against compute, memory, latency, and action-label cost. The field is moving toward methods that generate less of the future while preserving what control requires. The survey homepage is available at https://world-action-models.github.io/.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20781.png", "numComments": 1, "submittedBy": {"_id": "643a6e89a856622f9788bf67", "avatarUrl": "/avatars/419c0379f072295b27d4bfe2f8fb946d.svg", "fullname": "qiuhong shen", "name": "florinshum", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 10, "isUserFollowing": false}, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.22883", "authors": [{"_id": "6a3a09ebfdcd3514343bb61c", "name": "Zhanbo Hua", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61d", "name": "Yifan Yao", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61e", "name": "Weihao Xie", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb61f", "name": "Yongchi Zhao", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb620", "user": {"_id": "6417d9ea8f689506e7148417", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6417d9ea8f689506e7148417/bAYcruWNw4WvmuQcGgcwC.jpeg", "isPro": false, "fullname": "minghao", "user": "Liam-Liu", "type": "user", "name": "Liam-Liu"}, "name": "Minghao Liu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:14.672Z", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb621", "name": "Ruizhi Qiu", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb622", "name": "Zhewei Huang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb623", "name": "Zun Wang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb624", "name": "Yiyan Ji", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb625", "name": "Yunhai Ye", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb626", "name": "Letian Zhu", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb627", "name": "Xinping Lei", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb628", "name": "Han Li", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb629", "name": "Zhiyuan Ma", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62a", "name": "Zili Wang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62b", "name": "Zhaoxiang Zhang", "hidden": false}, {"_id": "6a3a09ebfdcd3514343bb62c", "name": "Jiaheng Liu", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "CLI-Universe: Towards Verifiable Task Synthesis Engine for Terminal Agents", "submittedOnDailyBy": {"_id": "65377c30e48353201e6fdda0", "avatarUrl": "/avatars/a8f803b6f2e598eaee9c52c0d2ddfc16.svg", "isPro": false, "fullname": "Jiaheng Liu", "user": "CheeryLJH", "type": "user", "name": "CheeryLJH"}, "summary": "While recent LLM-based terminal agents have demonstrated promising capabilities, the scarcity of high-quality, executable training data remains a critical bottleneck. Existing synthesis pipelines typically scale by retrofitting surface-level artifacts into tasks, frequently yielding ambiguous instructions, shallow execution paths, and brittle tests that provide weak learning signals. To overcome this, we introduce CLI-Universe, a principled synthesis engine that constructs terminal-agent tasks. CLI-Universe generates candidate tasks by sampling combinations across a multi-dimensional capability taxonomy (domain, skill type, capability, and engineering pillar), then grounds each candidate through evidence-guided deep research over real-world technical materials. To ensure rigorous supervision, validated blueprints are instantiated into Dockerized environments and subjected to a multi-stage executable verification pipeline featuring rubric-gated test construction, hint-conditional filtering, and strict fail-to-pass checking. Across the full pipeline, from candidate generation to verification, approximately two-thirds of candidates are discarded, retaining only those that are genuine, verifiable, and non-trivially challenging. To validate our framework, we instantiate a highly distilled dataset of 6,000 trajectories called CLI-Universe-6K. Remarkably, fine-tuning Qwen3-32B on CLI-Universe-6K achieves 33.4% on Terminal-Bench 2.0. This sets a new state-of-the-art for models trained on open-source data at or below 32B parameters, and outperforms several models an order of magnitude larger, demonstrating the profound data efficiency of structured, high-fidelity synthesis.", "upvotes": 27, "discussionId": "6a3a09ebfdcd3514343bb62d", "ai_summary": "A principled synthesis engine generates high-quality terminal-agent tasks through multi-dimensional capability taxonomy and evidence-guided research, creating a distilled dataset that enables significant performance gains in LLM training.", "ai_keywords": ["LLM-based terminal agents", "executable training data", "synthesis engine", "capability taxonomy", "evidence-guided deep research", "Dockerized environments", "executable verification pipeline", "rubric-gated test construction", "fail-to-pass checking", "Terminal-Bench 2.0", "Qwen3-32B", "CLI-Universe-6K"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68edc767abe005ac1b354573", "name": "NJU-LINK", "fullname": "NJU-LINK Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67f9d060395fb1a0d7e4ae21/O3V4UZjcSGnOivcQqTcXW.png"}, "summary_zh": "<ul>\n    <li>\u5f53\u524d\u57fa\u4e8e\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u7684\u7ec8\u7aef\u4ee3\u7406\u9762\u4e34\u9ad8\u8d28\u91cf\u53ef\u6267\u884c\u8bad\u7ec3\u6570\u636e\u4e0d\u8db3\u7684\u95ee\u9898\u3002</li>\n    <li>\u73b0\u6709\u7684\u6570\u636e\u5408\u6210\u6d41\u7a0b\u901a\u5e38\u751f\u6210\u6a21\u7cca\u6307\u4ee4\u548c\u8106\u5f31\u6d4b\u8bd5\uff0c\u5bfc\u81f4\u5b66\u4e60\u4fe1\u53f7\u8f83\u5f31\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86CLI-Universe\uff0c\u4e00\u4e2a\u7cfb\u7edf\u5316\u7684\u5408\u6210\u5f15\u64ce\uff0c\u7528\u4e8e\u6784\u5efa\u7ec8\u7aef\u4ee3\u7406\u4efb\u52a1\u3002</li>\n    <li>CLI-Universe\u901a\u8fc7\u771f\u5b9e\u6280\u672f\u6750\u6599\u7684\u6df1\u5ea6\u7814\u7a76\u751f\u6210\u5019\u9009\u4efb\u52a1\uff0c\u5e76\u5728\u4e25\u683c\u7684\u9a8c\u8bc1\u6d41\u7a0b\u4e2d\u7b5b\u9009\u6709\u6548\u4efb\u52a1\u3002</li>\n    <li>\u901a\u8fc7\u5728CLI-Universe-6K\u6570\u636e\u96c6\u4e0a\u5fae\u8c03Qwen3-32B\u6a21\u578b\uff0c\u8fbe\u5230\u4e86\u65b0\u7684\u6027\u80fd\u6807\u51c6\uff0c\u663e\u793a\u51fa\u9ad8\u6548\u7684\u6570\u636e\u5408\u6210\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current terminal agents using large language models (LLMs) struggle due to a lack of high-quality training data.</li>\n    <li>Existing methods often create unclear instructions and weak tests, leading to poor learning outcomes.</li>\n    <li>CLI-Universe is a new tool that generates better training tasks by combining different capabilities and using real-world resources for validation.</li>\n    <li>It includes a rigorous process to verify tasks, discarding about two-thirds of generated candidates to ensure quality and challenge.</li>\n    <li>Using a refined dataset called CLI-Universe-6K, a model achieved a new record in performance, highlighting the effectiveness of high-quality data synthesis.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "CLI-Universe: Towards Verifiable Task Synthesis Engine for Terminal Agents", "summary": "While recent LLM-based terminal agents have demonstrated promising capabilities, the scarcity of high-quality, executable training data remains a critical bottleneck. Existing synthesis pipelines typically scale by retrofitting surface-level artifacts into tasks, frequently yielding ambiguous instructions, shallow execution paths, and brittle tests that provide weak learning signals. To overcome this, we introduce CLI-Universe, a principled synthesis engine that constructs terminal-agent tasks. CLI-Universe generates candidate tasks by sampling combinations across a multi-dimensional capability taxonomy (domain, skill type, capability, and engineering pillar), then grounds each candidate through evidence-guided deep research over real-world technical materials. To ensure rigorous supervision, validated blueprints are instantiated into Dockerized environments and subjected to a multi-stage executable verification pipeline featuring rubric-gated test construction, hint-conditional filtering, and strict fail-to-pass checking. Across the full pipeline, from candidate generation to verification, approximately two-thirds of candidates are discarded, retaining only those that are genuine, verifiable, and non-trivially challenging. To validate our framework, we instantiate a highly distilled dataset of 6,000 trajectories called CLI-Universe-6K. Remarkably, fine-tuning Qwen3-32B on CLI-Universe-6K achieves 33.4% on Terminal-Bench 2.0. This sets a new state-of-the-art for models trained on open-source data at or below 32B parameters, and outperforms several models an order of magnitude larger, demonstrating the profound data efficiency of structured, high-fidelity synthesis.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22883.png", "numComments": 1, "submittedBy": {"_id": "65377c30e48353201e6fdda0", "avatarUrl": "/avatars/a8f803b6f2e598eaee9c52c0d2ddfc16.svg", "fullname": "Jiaheng Liu", "name": "CheeryLJH", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 29, "isUserFollowing": false}, "organization": {"_id": "68edc767abe005ac1b354573", "name": "NJU-LINK", "fullname": "NJU-LINK Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67f9d060395fb1a0d7e4ae21/O3V4UZjcSGnOivcQqTcXW.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.20515", "authors": [{"_id": "6a34b8084c5c5e0d69bf1cbc", "name": "Yalun Dai", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cbd", "name": "Hao Li", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cbe", "user": {"_id": "6658d01c6f1a71ba56d6c273", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/tc4nZrMuZQLfgt5aVxtH4.jpeg", "isPro": false, "fullname": "Tian Shulin", "user": "shulin16", "type": "user", "name": "shulin16"}, "name": "Shulin Tian", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:19:36.809Z", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cbf", "name": "Runmao Yao", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc0", "name": "Yuhao Dong", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc1", "name": "Fangzhou Hong", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc2", "name": "Zhaoxi Chen", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc3", "name": "Fangfu Liu", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc4", "name": "Baoliang Tian", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc5", "name": "Dingwen Zhang", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc6", "name": "Tao Wang", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc7", "name": "Kim-Hui Yap", "hidden": false}, {"_id": "6a34b8084c5c5e0d69bf1cc8", "name": "Ziwei Liu", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/667b8de7a68bf81afe668afe/nexnSTuenbS1WDVnwai4f.mp4"], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "S-Agent: Spatial Tool-Use Elicits Reasoning for Spatial Intelligence", "submittedOnDailyBy": {"_id": "667b8de7a68bf81afe668afe", "avatarUrl": "/avatars/aeff10805ff858332e6f6a58735dbbd9.svg", "isPro": false, "fullname": "leoli", "user": "lifuguan", "type": "user", "name": "lifuguan"}, "summary": "Real-world spatial intelligence requires reasoning over a continuous and evolving 3D world, yet existing VLMs and tool-augmented agents largely remain tied to static, stateless inference from isolated visual observations. We introduce \\textsc{S-Agent}, a spatial tool-use agentic paradigm for understanding and reasoning over continuous multi-view images and videos. By formulating spatial reasoning as spatio-temporal evidence accumulation rather than isolated frame-level prediction, S-Agent reshapes spatial perception into scene-centric understanding beyond frame-centric recognition. Specifically, S-Agent casts the VLM as a semantic planner that decides what evidence is needed, while a hierarchy of spatial tools and experts grounds objects in 2D, lifts them into 3D geometric evidence, and aggregates this evidence into high-level spatial knowledge (e.g., counting, measurement, orientation, and relative position). Additionally, a temporal memory mechanism, including Scene Memory for maintaining the evolving scene state and Agent Memory for accumulating reasoning context, enables evidence integration across frames and reasoning steps. Comprehensive experiments on multi-view and video spatial reasoning benchmarks show that S-Agent consistently improves both open-source and closed-source VLMs in a training-free manner. Beyond inference-time augmentation, supervised fine-tuning (SFT) on S-Agent-generated spatial trajectories S-300K yields S-Agent-8B, a compact spatial agent that significantly surpasses similar-scale baselines (e.g., Qwen3-VL-8B) and performs comparably to advanced closed-source models (e.g., GPT-5.4 and Gemini 3).", "upvotes": 27, "discussionId": "6a34b8094c5c5e0d69bf1cc9", "projectPage": "https://ropedia.github.io/S-Agent", "githubRepo": "https://github.com/Ropedia/S-Agent", "githubRepoAddedBy": "user", "ai_summary": "S-Agent is a spatial reasoning framework that enhances visual language models with temporal memory and hierarchical spatial tools to enable continuous 3D world understanding from multi-view imagery.", "ai_keywords": ["spatial reasoning", "visual language models", "temporal memory mechanism", "scene memory", "agent memory", "spatial tools", "3D geometric evidence", "spatio-temporal evidence accumulation", "multi-view images", "video spatial reasoning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 21, "organization": {"_id": "69b1179815ed2b14d9bcea99", "name": "ropedia-ai", "fullname": "Ropedia", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/69b116c65a198623dcbcc950/QFbPRKJTaUrMeF_rk7_4x.jpeg"}, "summary_zh": "<ul>\n    <li>\u73b0\u6709\u7684\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff08VLM\uff09\u548c\u5de5\u5177\u589e\u5f3a\u4ee3\u7406\u4e3b\u8981\u4f9d\u8d56\u4e8e\u9759\u6001\u3001\u65e0\u72b6\u6001\u7684\u89c6\u89c9\u89c2\u5bdf\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86S-Agent\uff0c\u4e00\u4e2a\u7528\u4e8e\u7406\u89e3\u548c\u63a8\u7406\u8fde\u7eed\u591a\u89c6\u89d2\u56fe\u50cf\u548c\u89c6\u9891\u7684\u7a7a\u95f4\u5de5\u5177\u4f7f\u7528\u4ee3\u7406\u6a21\u578b\u3002</li>\n    <li>S-Agent\u901a\u8fc7\u65f6\u7a7a\u8bc1\u636e\u79ef\u7d2f\u7684\u65b9\u5f0f\u8fdb\u884c\u7a7a\u95f4\u63a8\u7406\uff0c\u800c\u4e0d\u662f\u4ec5\u4ec5\u4f9d\u8d56\u4e8e\u5355\u5e27\u9884\u6d4b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5229\u7528\u5c42\u6b21\u5316\u7684\u7a7a\u95f4\u5de5\u5177\u548c\u4e13\u5bb6\uff0c\u5c06\u5bf9\u8c61\u4ece2D\u8f6c\u5316\u4e3a3D\u51e0\u4f55\u8bc1\u636e\uff0c\u5e76\u6574\u5408\u6210\u9ad8\u7ea7\u7a7a\u95f4\u77e5\u8bc6\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cS-Agent\u5728\u591a\u89c6\u89d2\u548c\u89c6\u9891\u7a7a\u95f4\u63a8\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u6027\u80fd\u4f18\u8d8a\uff0c\u4e14\u5728\u8bad\u7ec3\u65e0\u987b\u989d\u5916\u8c03\u6574\u3002 </li>\n</ul>", "summary_simple": "<ul>\n    <li>S-Agent is a new type of agent that helps understand and reason about 3D images and videos in a continuous way.</li>\n    <li>It focuses on gathering evidence from multiple views instead of just analyzing single frames.</li>\n    <li>S-Agent acts like a planner that determines what information is needed and uses various tools to gather and organize this information.</li>\n    <li>It has a memory system that helps keep track of changes in scenes over time and supports better reasoning.</li>\n    <li>Tests show that S-Agent improves performance of existing visual language models without needing extra training, and it can be further fine-tuned to outperform similar models.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "S-Agent: Spatial Tool-Use Elicits Reasoning for Spatial Intelligence", "summary": "Real-world spatial intelligence requires reasoning over a continuous and evolving 3D world, yet existing VLMs and tool-augmented agents largely remain tied to static, stateless inference from isolated visual observations. We introduce \\textsc{S-Agent}, a spatial tool-use agentic paradigm for understanding and reasoning over continuous multi-view images and videos. By formulating spatial reasoning as spatio-temporal evidence accumulation rather than isolated frame-level prediction, S-Agent reshapes spatial perception into scene-centric understanding beyond frame-centric recognition. Specifically, S-Agent casts the VLM as a semantic planner that decides what evidence is needed, while a hierarchy of spatial tools and experts grounds objects in 2D, lifts them into 3D geometric evidence, and aggregates this evidence into high-level spatial knowledge (e.g., counting, measurement, orientation, and relative position). Additionally, a temporal memory mechanism, including Scene Memory for maintaining the evolving scene state and Agent Memory for accumulating reasoning context, enables evidence integration across frames and reasoning steps. Comprehensive experiments on multi-view and video spatial reasoning benchmarks show that S-Agent consistently improves both open-source and closed-source VLMs in a training-free manner. Beyond inference-time augmentation, supervised fine-tuning (SFT) on S-Agent-generated spatial trajectories S-300K yields S-Agent-8B, a compact spatial agent that significantly surpasses similar-scale baselines (e.g., Qwen3-VL-8B) and performs comparably to advanced closed-source models (e.g., GPT-5.4 and Gemini 3).", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/667b8de7a68bf81afe668afe/nexnSTuenbS1WDVnwai4f.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20515.png", "numComments": 1, "submittedBy": {"_id": "667b8de7a68bf81afe668afe", "avatarUrl": "/avatars/aeff10805ff858332e6f6a58735dbbd9.svg", "fullname": "leoli", "name": "lifuguan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "69b1179815ed2b14d9bcea99", "name": "ropedia-ai", "fullname": "Ropedia", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/69b116c65a198623dcbcc950/QFbPRKJTaUrMeF_rk7_4x.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.20517", "authors": [{"_id": "6a3510a2156f0a50f94c1add", "name": "Maria Ivanova", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ade", "name": "Pavel Zadorozhny", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1adf", "name": "Rodion Levichev", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ae0", "name": "Ivan Petrov", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ae1", "name": "Adamenko Pavel", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ae2", "name": "Ivan Lopatin", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ae3", "name": "Alexey Kutalev", "hidden": false}, {"_id": "6a3510a2156f0a50f94c1ae4", "name": "Dmitrii Babaev", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/-NMjA2FhOoF-Fk1ep6zSv.png", "https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/mmt8MIuLJmG7UqkVdIgJM.png", "https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/zG7QQLug7eHcu8AR6Kafy.png"], "publishedAt": "2026-06-18T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "Multi-LCB: Extending LiveCodeBench to Multiple Programming Languages", "submittedOnDailyBy": {"_id": "626474fc247eba6089349be1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/qrakyLlNdJBjgUURsDgQP.png", "isPro": false, "fullname": "Dmitri Babaev", "user": "dllllb", "type": "user", "name": "dllllb"}, "summary": "LiveCodeBench (LCB) has recently become a widely adopted benchmark for evaluating large language models (LLMs) on code-generation tasks. By curating competitive programming problems, constantly adding fresh problems to the set, and filtering them by release dates, LCB provides contamination-aware evaluation and offers a holistic view of coding capability. However, LCB remains restricted to Python, leaving open the question of whether LLMs can generalize across the diverse programming languages required in real-world software engineering.\n  We introduce Multi-LCB, a benchmark for evaluating LLMs across twelve programming languages, including Python. Multi-LCB transforms Python tasks from the LCB dataset into equivalent tasks in other languages while preserving LCB's contamination controls and evaluation protocol. Because it is fully compatible with the original LCB format, Multi-LCB will automatically track future LCB updates, enabling systematic assessment of cross-language code generation competence and requiring models to sustain performance well beyond Python.\n  We evaluated 24 LLMs for instruction and reasoning on Multi-LCB, uncovering evidence of Python overfitting, language-specific contamination, and substantial disparities in multilingual performance. Our results establish Multi-LCB as a rigorous new benchmark for multi-programming-language code evaluation, directly addressing LCB's primary limitation and exposing critical gaps in current LLM capabilities.", "upvotes": 26, "discussionId": "6a3510a3156f0a50f94c1ae5", "projectPage": "https://multi-lcb.github.io/", "githubRepo": "https://github.com/Multi-LCB/Multi-LCB", "githubRepoAddedBy": "user", "ai_summary": "Multi-LCB addresses the limitation of LiveCodeBench by providing a multi-language benchmark for evaluating LLMs across twelve programming languages while maintaining contamination controls and evaluation protocols.", "ai_keywords": ["large language models", "code-generation tasks", "competitive programming problems", "contamination-aware evaluation", "cross-language code generation", "multilingual performance", "Python overfitting", "language-specific contamination"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 22, "summary_zh": "<ul>\n    <li>LiveCodeBench\uff08LCB\uff09\u662f\u4e00\u4e2a\u7528\u4e8e\u8bc4\u4f30\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u5728\u4ee3\u7801\u751f\u6210\u4efb\u52a1\u7684\u57fa\u51c6\uff0c\u76ee\u524d\u5e7f\u53d7\u6b22\u8fce\u3002</li>\n    <li>LCB \u4e3b\u8981\u96c6\u4e2d\u5728 Python \u8bed\u8a00\uff0c\u5b58\u5728\u8bc4\u4f30\u6a21\u578b\u5728\u5176\u4ed6\u7f16\u7a0b\u8bed\u8a00\u4e0a\u7684\u80fd\u529b\u4e0d\u8db3\u7684\u95ee\u9898\u3002</li>\n    <li>Multi-LCB \u662f\u4e00\u4e2a\u65b0\u57fa\u51c6\uff0c\u80fd\u591f\u5728\u5305\u62ec Python \u5728\u5185\u7684\u5341\u4e8c\u79cd\u7f16\u7a0b\u8bed\u8a00\u4e2d\u8bc4\u4f30 LLMs\u3002</li>\n    <li>Multi-LCB \u901a\u8fc7\u5c06 LCB \u7684 Python \u4efb\u52a1\u8f6c\u6362\u4e3a\u5176\u4ed6\u8bed\u8a00\u7684\u7b49\u6548\u4efb\u52a1\uff0c\u540c\u65f6\u4fdd\u6301\u8bc4\u4f30\u6807\u51c6\u3002</li>\n    <li>\u5bf9 24 \u4e2a LLMs \u7684\u8bc4\u4f30\u663e\u793a\u4e86 Python \u8fc7\u62df\u5408\u548c\u591a\u8bed\u8a00\u6027\u80fd\u5dee\u5f02\uff0c\u5f3a\u8c03\u4e86\u5f53\u524d LLM \u529f\u80fd\u7684\u5173\u952e\u7f3a\u53e3\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>LiveCodeBench (LCB) is a popular benchmark for testing large language models (LLMs) on coding tasks but only supports Python.</li>\n    <li>Multi-LCB is introduced as a new benchmark that evaluates LLMs across twelve programming languages, including Python.</li>\n    <li>Multi-LCB adapts tasks from the LCB dataset to other languages while maintaining LCB's evaluation standards.</li>\n    <li>The benchmark allows for tracking updates from LCB and helps assess LLM performance across different languages.</li>\n    <li>Evaluation of 24 LLMs on Multi-LCB revealed issues like Python overfitting and varied performance across languages, highlighting weaknesses in current LLMs.</li>\n</ul>"}, "publishedAt": "2026-06-17T20:00:00.000Z", "title": "Multi-LCB: Extending LiveCodeBench to Multiple Programming Languages", "summary": "LiveCodeBench (LCB) has recently become a widely adopted benchmark for evaluating large language models (LLMs) on code-generation tasks. By curating competitive programming problems, constantly adding fresh problems to the set, and filtering them by release dates, LCB provides contamination-aware evaluation and offers a holistic view of coding capability. However, LCB remains restricted to Python, leaving open the question of whether LLMs can generalize across the diverse programming languages required in real-world software engineering.\n  We introduce Multi-LCB, a benchmark for evaluating LLMs across twelve programming languages, including Python. Multi-LCB transforms Python tasks from the LCB dataset into equivalent tasks in other languages while preserving LCB's contamination controls and evaluation protocol. Because it is fully compatible with the original LCB format, Multi-LCB will automatically track future LCB updates, enabling systematic assessment of cross-language code generation competence and requiring models to sustain performance well beyond Python.\n  We evaluated 24 LLMs for instruction and reasoning on Multi-LCB, uncovering evidence of Python overfitting, language-specific contamination, and substantial disparities in multilingual performance. Our results establish Multi-LCB as a rigorous new benchmark for multi-programming-language code evaluation, directly addressing LCB's primary limitation and exposing critical gaps in current LLM capabilities.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/-NMjA2FhOoF-Fk1ep6zSv.png", "https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/mmt8MIuLJmG7UqkVdIgJM.png", "https://cdn-uploads.huggingface.co/production/uploads/626474fc247eba6089349be1/zG7QQLug7eHcu8AR6Kafy.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.20517.png", "numComments": 3, "submittedBy": {"_id": "626474fc247eba6089349be1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/qrakyLlNdJBjgUURsDgQP.png", "fullname": "Dmitri Babaev", "name": "dllllb", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.21649", "authors": [{"_id": "6a39e797fdcd3514343bb4c2", "user": {"_id": "69b14cdeeed94a88011ce095", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/1LRe2njtqTGIsBTkOSIOT.jpeg", "isPro": false, "fullname": "Nie", "user": "ClareNie", "type": "user", "name": "ClareNie"}, "name": "Chang Nie", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:58.268Z", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c3", "name": "Chaoyou Fu", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c4", "name": "Junlan Feng", "hidden": false}, {"_id": "6a39e797fdcd3514343bb4c5", "name": "Caifeng Shan", "hidden": false}], "publishedAt": "2026-06-19T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "EvoEmbedding: Evolvable Representations for Long-Context Retrieval and Agentic Memory", "submittedOnDailyBy": {"_id": "653b268cd1041ca9188954da", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/653b268cd1041ca9188954da/5Qy0fyQdRCIUUAzV6fg1k.png", "isPro": false, "fullname": "Chaoyou Fu", "user": "BradyFU", "type": "user", "name": "BradyFU"}, "summary": "Existing embedding models are inherently static: they encode text segments in isolation, ignoring their surrounding context and temporal order. This paper introduces EvoEmbedding, a novel embedding model that generates evolvable representations for retrieval. It is tailored for long-context scenarios, where information is dynamic, sequential, and requires continuous state tracking. Our design is simple: EvoEmbedding maintains a continuously updated latent memory as it sequentially processes inputs, and uses it alongside the raw content to jointly generate evolvable embeddings. Consequently, for the same query, our model adapts its representation to retrieve distinct targets based on the evolving context, going beyond static semantic search. To equip the model with this capability, we construct EvoTrain-180K, a diverse dataset for the joint optimization of latent memory and retrieval. Furthermore, we introduce a memory queue to prevent representation collapse during recurrent encoding, alongside segment-batching techniques that tackle significant length variance and accelerate training by 3.8times. Extensive experiments show that our model not only outperforms larger-scale specialists (e.g., Qwen3-Embedding-8B and KaLM-Embedding-Gemma3-12B) across a range of long-context retrieval benchmarks, but also generalizes well to downstream tasks (e.g., personalization) with contexts 10times longer than its training window. Notably, EvoEmbedding seamlessly integrates into agentic workflows to boost performance. For instance, a naive RAG pipeline equipped with our model surpasses dedicated agentic memory systems. Project Page: https://clare-nie.github.io/EvoEmbedding.", "upvotes": 24, "discussionId": "6a39e798fdcd3514343bb4c6", "projectPage": "https://clare-nie.github.io/EvoEmbedding/", "githubRepo": "https://github.com/MiG-NJU/EvoEmbedding", "githubRepoAddedBy": "user", "ai_summary": "EvoEmbedding is a dynamic embedding model that generates adaptive representations by maintaining a continuously updated latent memory, enabling improved retrieval performance in long-context scenarios.", "ai_keywords": ["evolvable representations", "latent memory", "sequential processing", "joint generation", "representation collapse", "segment-batching", "long-context retrieval", "agentic workflows", "RAG pipeline"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 21, "organization": {"_id": "638f70e8f1256a80d4288555", "name": "nanjinguniv", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638f706ef1256a80d42880f9/6M6-JzwJGiLxjIJzvCflf.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u6709\u7684\u5d4c\u5165\u6a21\u578b\u662f\u9759\u6001\u7684\uff0c\u65e0\u6cd5\u8003\u8651\u6587\u672c\u7684\u4e0a\u4e0b\u6587\u548c\u65f6\u95f4\u987a\u5e8f\u3002</li>\n    <li>EvoEmbedding\u662f\u4e00\u79cd\u65b0\u578b\u5d4c\u5165\u6a21\u578b\uff0c\u80fd\u591f\u751f\u6210\u53ef\u6f14\u53d8\u7684\u8868\u793a\uff0c\u9002\u7528\u4e8e\u957f\u4e0a\u4e0b\u6587\u573a\u666f\u3002</li>\n    <li>\u8be5\u6a21\u578b\u901a\u8fc7\u6301\u7eed\u66f4\u65b0\u7684\u6f5c\u5728\u8bb0\u5fc6\u6765\u5904\u7406\u8f93\u5165\uff0c\u5e76\u4e0e\u539f\u59cb\u5185\u5bb9\u4e00\u8d77\u751f\u6210\u5d4c\u5165\u3002</li>\n    <li>EvoEmbedding\u5728\u68c0\u7d22\u65f6\u80fd\u591f\u6839\u636e\u4e0d\u65ad\u53d8\u5316\u7684\u4e0a\u4e0b\u6587\u8c03\u6574\u8868\u793a\uff0c\u8d85\u8d8a\u4e86\u9759\u6001\u8bed\u4e49\u641c\u7d22\u3002</li>\n    <li>\u6a21\u578b\u5728\u591a\u4e2a\u957f\u4e0a\u4e0b\u6587\u68c0\u7d22\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8d85\u8d8a\u4e86\u66f4\u5927\u89c4\u6a21\u7684\u4e13\u7528\u6a21\u578b\uff0c\u5e76\u80fd\u5f88\u597d\u5730\u9002\u5e94\u4e0b\u6e38\u4efb\u52a1\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>EvoEmbedding is a new model that creates flexible text representations for better information retrieval.</li>\n    <li>It processes information in a sequence, keeping track of context and changes over time.</li>\n    <li>The model updates its memory continuously, allowing it to adapt responses based on evolving situations.</li>\n    <li>EvoEmbedding has been trained on a large dataset and shows improved performance in retrieving long-context information compared to other models.</li>\n    <li>It works well in various applications and can enhance workflows, outperforming traditional memory systems.</li>\n</ul>"}, "publishedAt": "2026-06-18T20:00:00.000Z", "title": "EvoEmbedding: Evolvable Representations for Long-Context Retrieval and Agentic Memory", "summary": "Existing embedding models are inherently static: they encode text segments in isolation, ignoring their surrounding context and temporal order. This paper introduces EvoEmbedding, a novel embedding model that generates evolvable representations for retrieval. It is tailored for long-context scenarios, where information is dynamic, sequential, and requires continuous state tracking. Our design is simple: EvoEmbedding maintains a continuously updated latent memory as it sequentially processes inputs, and uses it alongside the raw content to jointly generate evolvable embeddings. Consequently, for the same query, our model adapts its representation to retrieve distinct targets based on the evolving context, going beyond static semantic search. To equip the model with this capability, we construct EvoTrain-180K, a diverse dataset for the joint optimization of latent memory and retrieval. Furthermore, we introduce a memory queue to prevent representation collapse during recurrent encoding, alongside segment-batching techniques that tackle significant length variance and accelerate training by 3.8times. Extensive experiments show that our model not only outperforms larger-scale specialists (e.g., Qwen3-Embedding-8B and KaLM-Embedding-Gemma3-12B) across a range of long-context retrieval benchmarks, but also generalizes well to downstream tasks (e.g., personalization) with contexts 10times longer than its training window. Notably, EvoEmbedding seamlessly integrates into agentic workflows to boost performance. For instance, a naive RAG pipeline equipped with our model surpasses dedicated agentic memory systems. Project Page: https://clare-nie.github.io/EvoEmbedding.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.21649.png", "numComments": 3, "submittedBy": {"_id": "653b268cd1041ca9188954da", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/653b268cd1041ca9188954da/5Qy0fyQdRCIUUAzV6fg1k.png", "fullname": "Chaoyou Fu", "name": "BradyFU", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 8, "isUserFollowing": false}, "organization": {"_id": "638f70e8f1256a80d4288555", "name": "nanjinguniv", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/638f706ef1256a80d42880f9/6M6-JzwJGiLxjIJzvCflf.png"}, "isAuthorParticipating": true}],
    "month": [{"paper": {"id": "2606.09967", "authors": [{"_id": "6a28c3c5e7d78ea7587e52bd", "name": "Ming Qian", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52be", "name": "Tianjian Ouyang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52bf", "name": "Mingchao Sun", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c0", "name": "Zijian Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c1", "name": "Jincheng Xiong", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c2", "name": "Jiarong Han", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c3", "name": "Yongchang Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c4", "name": "Jiawei Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c5", "name": "Xu Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c6", "name": "Yu Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c7", "name": "Luyang Tang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c8", "name": "Fei Yu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c9", "name": "Zengye Ge", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ca", "name": "Mengmeng Du", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cb", "name": "Yuan Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cc", "name": "Nianfei Fan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cd", "name": "Song Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ce", "name": "Yingliang Peng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cf", "name": "Chunxue Jia", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d0", "name": "Yang Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d1", "name": "Shiying Zeng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d2", "name": "Haozhe Shi", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d3", "name": "Junnan Lai", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d4", "name": "Hongyu Pan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d5", "name": "Zheng Wu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d6", "name": "Ning Guo", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d7", "name": "Mu Xu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d8", "name": "Hang Zhang", "hidden": false}], "publishedAt": "2026-06-08T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "submittedOnDailyBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "isPro": false, "fullname": "qian#143", "user": "qian43", "type": "user", "name": "qian43"}, "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "upvotes": 194, "discussionId": "6a28c3c5e7d78ea7587e52d9", "projectPage": "https://abot-earth.amap.com/", "githubRepo": "https://github.com/amap-cvlab/ABot-Earth-0.5", "githubRepoAddedBy": "user", "ai_summary": "ABot-Earth 0.5 generates realistic 3D environments from satellite imagery using 3D Gaussian Splatting representation, enabling fast synthesis and real-time visualization for Embodied AI applications.", "ai_keywords": ["3D Gaussian Splatting", "generative model", "satellite imagery", "3D environment synthesis", "level-of-detail", "real-time visualization", "Embodied AI", "UAV navigation", "digital earth visualization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 109, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "summary_zh": "<ul>\n    <li>ABot-Earth 0.5 \u662f\u4e00\u4e2a\u751f\u6210\u6027 3D \u6846\u67b6\uff0c\u53ef\u4ee5\u6839\u636e\u536b\u661f\u5f71\u50cf\u5408\u6210\u5e7f\u9614\u65e0\u7f1d\u7684 3D \u73af\u5883\u3002</li>\n    <li>\u8be5\u6a21\u578b\u4f7f\u7528\u65b0\u7684 3D \u9ad8\u65af\u70b9\u4e91\u8868\u793a\uff0c\u7ecf\u8fc7\u591a\u6837\u7684\u73b0\u5b9e\u57ce\u5e02\u91cd\u5efa\u6570\u636e\u8bad\u7ec3\uff0c\u80fd\u591f\u751f\u6210\u771f\u5b9e\u7684\u51e0\u4f55\u548c\u7eb9\u7406\u3002</li>\n    <li>\u5408\u6210\u65b0 3D \u573a\u666f\u7684\u901f\u5ea6\u975e\u5e38\u5feb\uff0c\u6bcf\u5e73\u65b9\u516c\u91cc\u53ea\u9700\u4e0d\u523010\u5206\u949f\uff0c\u4e14\u5177\u6709\u6781\u9ad8\u7684\u771f\u5b9e\u611f\u3002</li>\n    <li>\u6846\u67b6\u8bbe\u8ba1\u4fbf\u4e8e\u4f7f\u7528\uff0c\u652f\u6301\u5b9e\u65f6\u4e92\u52a8\u53ef\u89c6\u5316\uff0c\u9002\u7528\u4e8e\u7f51\u9875\u5730\u56fe\u5f15\u64ce\u3002</li>\n    <li>ABot-Earth 0.5 \u964d\u4f4e\u4e86\u5927\u89c4\u6a21 3D \u91cd\u5efa\u7684\u6280\u672f\u548c\u7ecf\u6d4e\u95e8\u69db\uff0c\u63a8\u52a8\u5168\u7403\u6570\u5b57\u5730\u7403\u53ef\u89c6\u5316\u7684\u672a\u6765\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ABot-Earth 0.5 is a tool that creates detailed 3D environments using satellite images.</li>\n    <li>It uses a unique model that learns from real-world city designs to produce realistic 3D scenes.</li>\n    <li>The system can generate new 3D scenes quickly, taking less than 10 minutes for each square kilometer.</li>\n    <li>It allows for real-time interactive visualization on web maps and is designed to be easy to use.</li>\n    <li>ABot-Earth 0.5 makes 3D reconstruction cheaper and easier, supporting advanced applications like drone navigation.</li>\n</ul>"}, "publishedAt": "2026-06-07T20:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.09967.png", "numComments": 3, "submittedBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "fullname": "qian#143", "name": "qian43", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u63a8\u51fa\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u4e00\u4e2a\u5f00\u6e90\u7684\u6df7\u5408\u4e13\u5bb6\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u63d0\u5347\u957f\u89c6\u9891\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\u673a\u5236\uff0c\u80fd\u591f\u5904\u7406256K\u4e0a\u4e0b\u6587\uff0c\u6355\u6349\u5173\u952e\u5e27\u548c\u957f\u65f6\u95f4\u4f9d\u8d56\u5173\u7cfb\u3002</li>\n    <li>\u901a\u8fc7\u4f18\u5316\u8bad\u7ec3\u548c\u63a8\u7406\u57fa\u7840\u8bbe\u65bd\uff0c\u63d0\u9ad8\u4e86\u89c6\u9891\u8f93\u5165\u8f93\u51fa\u7684\u53ef\u6269\u5c55\u6027\u548c\u8ba1\u7b97\u6548\u7387\u3002</li>\n    <li>\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u65b9\u6cd5\uff0c\u89e3\u51b3\u4e86\u591a\u4efb\u52a1\u5bf9\u9f50\u4e2d\u7684\u707e\u96be\u6027\u9057\u5fd8\u95ee\u9898\u3002</li>\n    <li>\u5728\u89c6\u9891\u7406\u89e3\u3001\u65f6\u95f4\u5b9a\u4f4d\u548c\u957f\u89c6\u9891\u7406\u89e3\u7b49\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u53d1\u5e03\u6a21\u578b\u68c0\u67e5\u70b9\u4ee5\u4fc3\u8fdb\u793e\u533a\u7684\u8fdb\u6b65\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Kwai Keye-VL-2.0-30B-A3B is a new open-source multimodal model designed for better understanding of long videos and improving intelligent agents.</li>\n  <li>It uses DeepSeek Sparse Attention to handle very long video contexts efficiently, allowing it to process up to 256K data without losing important information.</li>\n  <li>The model features advanced training techniques to prevent losing information when learning multiple tasks, enhancing its ability to work with different kinds of data.</li>\n  <li>Keye-VL-2.0-30B-A3B shows top performance in video understanding and reasoning tasks compared to similar models, especially in precise time localization and comprehension of long videos.</li>\n  <li>The creators are sharing the model's checkpoints to help others develop better multimodal applications.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.14777", "authors": [{"_id": "6a30c3bfa0d4daae4285fefd", "name": "Dingyu Yao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285fefe", "name": "Junhao Zhou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285feff", "user": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "name": "Chenxu Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T16:15:00.215Z", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff00", "name": "Chuanyu Qin", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff01", "name": "Haowen Hou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff02", "name": "Zheming Liang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff03", "name": "Congcong Wang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff04", "name": "Yuhang Cao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff05", "name": "Shenglong Ye", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff06", "name": "Shuai Xie", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff07", "name": "Shuhuan Gu", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff08", "name": "Haoyang Huang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff09", "name": "Qingyi Si", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0a", "name": "Nan Duan", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0b", "user": {"_id": "64b4eec4faa3181a5eab9c46", "avatarUrl": "/avatars/bcc9bf5cbf67546ad2b4c9ec8b96ac96.svg", "isPro": true, "fullname": "Jiaqi Wang", "user": "myownskyW7", "type": "user", "name": "myownskyW7"}, "name": "Jiaqi Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T12:05:58.790Z", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "submittedOnDailyBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "upvotes": 157, "discussionId": "6a30c3bfa0d4daae4285ff0c", "projectPage": "https://joyai-vl-video-future-academy-jd.github.io/JoyAI-VL-Interaction/", "githubRepo": "https://github.com/jd-opensource/JoyAI-VL-Interaction", "githubRepoAddedBy": "user", "ai_summary": "A vision-language model operates continuously in real-time, making autonomous decisions about when to respond or delegate, enabling interactive systems that perceive and act upon environmental changes without user prompting.", "ai_keywords": ["vision-language model", "real-time interaction", "autonomous decision-making", "vision-triggered responsiveness", "time awareness", "background model", "deployable system", "video streaming", "interactive AI", "continuous perception"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 209, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u5b9e\u4e16\u754c\u4e2d\u8bb8\u591a\u65f6\u523b\u5e76\u4e0d\u4f1a\u7b49\u7528\u6237\u63d0\u95ee\uff0c\u5982\u76d1\u89c6\u5668\u4e0a\u7684\u706b\u707e\u3001\u89c6\u9891\u901a\u8bdd\u4e2d\u7684\u8868\u60c5\u6216\u76f4\u64ad\u4e2d\u7684\u4ea7\u54c1\u3002</li>\n    <li>\u73b0\u6709\u7684\u5927\u578b\u6a21\u578b\u4e3b\u8981\u662f\u57fa\u4e8e\u63d0\u95ee\u7684\u8bbe\u8ba1\uff0c\u53ea\u5728\u88ab\u95ee\u53ca\u65f6\u624d\u4f5c\u51fa\u53cd\u5e94\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u8303\u5f0f\uff1a\u6a21\u578b\u50cf\u4eba\u4e00\u6837\u6301\u7eed\u5173\u6ce8\u5468\u56f4\u53d1\u751f\u7684\u4e8b\u60c5\uff0c\u51b3\u5b9a\u4f55\u65f6\u8bf4\u8bdd\u6216\u4fdd\u6301\u6c89\u9ed8\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86JoyAI-VL-Interaction\uff0c\u4e00\u4e2a8B\u89c4\u6a21\u7684\u89c6\u89c9\u4f18\u5148\u4ea4\u4e92\u6a21\u578b\uff0c\u80fd\u591f\u5728\u5b9e\u65f6\u4e2d\u505a\u51fa\u53cd\u5e94\u51b3\u7b56\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5728\u516d\u4e2a\u73b0\u5b9e\u573a\u666f\u4e2d\u8868\u73b0\u4f18\u4e8e\u5176\u4ed6\u89c6\u9891\u901a\u8bdd\u52a9\u624b\uff0c\u4e14\u662f\u9996\u4e2a\u5f00\u653e\u7684\u89c6\u89c9\u9a71\u52a8\u4ea4\u4e92\u6a21\u578b\uff0c\u9644\u5e26\u8bad\u7ec3\u914d\u65b9\u548c\u5b8c\u6574\u53ef\u90e8\u7f72\u7cfb\u7edf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current AI models respond only when asked, missing real-time interactions found in real life.</li>\n    <li>The authors propose a new type of model that continuously observes and can respond actively, similar to a person.</li>\n    <li>They introduce JoyAI-VL-Interaction, an advanced model that decides when to respond or remain silent, focusing on visual awareness.</li>\n    <li>This model comes with a training recipe that allows it to adapt and perform tasks it wasn't specifically trained for.</li>\n    <li>The authors also provide a complete system that integrates this model with various components, showing better performance than existing video-call assistants.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.14777.png", "numComments": 2, "submittedBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "fullname": "steven young", "name": "iieycx", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.28816", "authors": [{"_id": "6a17a1c1b4840f905a67423f", "name": "Fangfu Liu", "hidden": false}, {"_id": "6a17a1c1b4840f905a674240", "name": "Kai He", "hidden": false}, {"_id": "6a17a1c1b4840f905a674241", "name": "Tianchang Shen", "hidden": false}, {"_id": "6a17a1c1b4840f905a674242", "name": "Tianshi Cao", "hidden": false}, {"_id": "6a17a1c1b4840f905a674243", "name": "Sanja Fidler", "hidden": false}, {"_id": "6a17a1c1b4840f905a674244", "name": "Yueqi Duan", "hidden": false}, {"_id": "6a17a1c1b4840f905a674245", "name": "Jun Gao", "hidden": false}, {"_id": "6a17a1c1b4840f905a674246", "name": "Igor Gilitschenski", "hidden": false}, {"_id": "6a17a1c1b4840f905a674247", "name": "Zian Wang", "hidden": false}, {"_id": "6a17a1c1b4840f905a674248", "name": "Xuanchi Ren", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/_NpefLBu0wIqfoZP0K0uR.png", "https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/A2fGxpraAXcD9_RIUiZX2.mp4"], "publishedAt": "2026-05-27T00:00:00.000Z", "submittedOnDailyAt": "2026-05-28T00:00:00.000Z", "title": "Gamma-World: Generative Multi-Agent World Modeling Beyond Two Players", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "World models for interactive video generation have largely focused on single-agent settings, where future observations are generated from a single control signal. However, many generated environments require multi-agent interaction: multiple players, robots, or embodied agents act simultaneously within a shared space. Scaling world models to such settings requires a principled multi-agent design: agents should remain independently controllable, permutation-symmetric, and support efficient inference while maintaining consistency across time and perspectives. In this paper, we present our generative multi-agent world model for interactive simulation. It introduces Simplex Rotary Agent Encoding, a parameter-free extension of 3D RoPE that represents agents as vertices of a regular simplex in rotary angle space. This gives each agent a distinct phase while making all agents permutation-equivalent, enabling scalable agent identity without learned per-slot identities or a fixed agent ordering. To avoid dense all-to-all attention across agents, we further propose Sparse Hub Attention, where learnable hub tokens mediate token interaction across agents, reducing cross-agent attention cost from quadratic to linear in the number of agents. For real-time rollout, we distill a full-context diffusion teacher into a causal student that generates temporal blocks sequentially with KV caching, enabling action-responsive generation at 24 FPS. Experiments in multiplayer virtual environments show that our model improves video fidelity, action controllability, and inter-agent consistency over slot-based and dense-attention baselines, while generalizing from two to four players without additional training.", "upvotes": 156, "discussionId": "6a17a1c2b4840f905a674249", "projectPage": "https://research.nvidia.com/labs/sil/projects/gamma-world/", "ai_summary": "A generative multi-agent world model is presented that uses simplex rotary agent encoding and sparse hub attention to enable scalable, permutation-symmetric interaction between multiple agents in interactive video generation.", "ai_keywords": ["world models", "multi-agent interaction", "rotary angle space", "permutation-symmetric", "sparse hub attention", "causal student", "KV caching", "diffusion teacher", "action-responsive generation"], "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u6709\u7684\u4e16\u754c\u6a21\u578b\u4e3b\u8981\u96c6\u4e2d\u5728\u5355\u4e00\u4ee3\u7406\u8bbe\u7f6e\uff0c\u800c\u8bb8\u591a\u751f\u6210\u73af\u5883\u9700\u8981\u591a\u4ee3\u7406\u4e92\u52a8\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u751f\u6210\u591a\u4ee3\u7406\u4e16\u754c\u6a21\u578b\uff0c\u5141\u8bb8\u72ec\u7acb\u63a7\u5236\u548c\u9ad8\u6548\u63a8\u7406\uff0c\u540c\u65f6\u4fdd\u6301\u65f6\u95f4\u548c\u89c6\u89d2\u4e00\u81f4\u6027\u3002</li>\n    <li>\u5f15\u5165\u4e86\u7b80\u5355\u65cb\u8f6c\u4ee3\u7406\u7f16\u7801\uff0c\u5c06\u4ee3\u7406\u8868\u793a\u4e3a\u65cb\u8f6c\u89d2\u7a7a\u95f4\u4e2d\u7684\u6b63\u7b80\u5355\u5f62\u72b6\u9876\u70b9\uff0c\u5b9e\u73b0\u4e86\u53ef\u6269\u5c55\u7684\u4ee3\u7406\u8eab\u4efd\u3002</li>\n    <li>\u63d0\u51fa\u7a00\u758f\u4e2d\u5fc3\u6ce8\u610f\u529b\uff0c\u51cf\u5c11\u8de8\u4ee3\u7406\u7684\u8ba1\u7b97\u6210\u672c\uff0c\u4f7f\u5f97\u6ce8\u610f\u529b\u4ece\u5e73\u65b9\u964d\u4f4e\u5230\u7ebf\u6027\u3002</li>\n    <li>\u5728\u591a\u73a9\u5bb6\u865a\u62df\u73af\u5883\u4e2d\u7684\u5b9e\u9a8c\u8868\u660e\uff0c\u6211\u4eec\u7684\u6a21\u578b\u5728\u89c6\u9891\u8d28\u91cf\u3001\u884c\u52a8\u53ef\u63a7\u6027\u548c\u4ee3\u7406\u4e00\u81f4\u6027\u65b9\u9762\u4f18\u4e8e\u73b0\u6709\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The paper discusses a new model for generating interactive videos with multiple agents, rather than just one.</li>\n    <li>It proposes a method called Simplex Rotary Agent Encoding to uniquely represent each agent while keeping them interchangeable.</li>\n    <li>The model uses Sparse Hub Attention to simplify how agents interact, making it faster and more efficient.</li>\n    <li>It can generate video in real-time at 24 frames per second, allowing for quick responses to actions.</li>\n    <li>Tests show that this model produces better video quality and teamwork among agents compared to previous methods.</li>\n</ul>"}, "publishedAt": "2026-05-26T20:00:00.000Z", "title": "Gamma-World: Generative Multi-Agent World Modeling Beyond Two Players", "summary": "World models for interactive video generation have largely focused on single-agent settings, where future observations are generated from a single control signal. However, many generated environments require multi-agent interaction: multiple players, robots, or embodied agents act simultaneously within a shared space. Scaling world models to such settings requires a principled multi-agent design: agents should remain independently controllable, permutation-symmetric, and support efficient inference while maintaining consistency across time and perspectives. In this paper, we present our generative multi-agent world model for interactive simulation. It introduces Simplex Rotary Agent Encoding, a parameter-free extension of 3D RoPE that represents agents as vertices of a regular simplex in rotary angle space. This gives each agent a distinct phase while making all agents permutation-equivalent, enabling scalable agent identity without learned per-slot identities or a fixed agent ordering. To avoid dense all-to-all attention across agents, we further propose Sparse Hub Attention, where learnable hub tokens mediate token interaction across agents, reducing cross-agent attention cost from quadratic to linear in the number of agents. For real-time rollout, we distill a full-context diffusion teacher into a causal student that generates temporal blocks sequentially with KV caching, enabling action-responsive generation at 24 FPS. Experiments in multiplayer virtual environments show that our model improves video fidelity, action controllability, and inter-agent consistency over slot-based and dense-attention baselines, while generalizing from two to four players without additional training.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/_NpefLBu0wIqfoZP0K0uR.png", "https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/A2fGxpraAXcD9_RIUiZX2.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.28816.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 307, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.18023", "authors": [{"_id": "6a3201f3bc818ff14e453d61", "name": "Jian Yang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d62", "name": "Shawn Guo", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d63", "name": "Wei Zhang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d64", "user": {"_id": "64ab99dcb76bfd863eba64c1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ab99dcb76bfd863eba64c1/UBXwDPx17X-gl-SzBPvrc.jpeg", "isPro": false, "fullname": "TY.Zheng", "user": "aaabiao", "type": "user", "name": "aaabiao"}, "name": "Tianyu Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:10.407Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d65", "name": "Yaxin Du", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d66", "name": "Haau-Sing Li", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d67", "user": {"_id": "66a8e2538407031e388c501f", "avatarUrl": "/avatars/d16d51f7b1e111efd6d0985995b614be.svg", "isPro": false, "fullname": "wjj", "user": "wuyuverse", "type": "user", "name": "wuyuverse"}, "name": "Jiajun Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:12.507Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d68", "name": "Yue Song", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d69", "name": "Yan Xing", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6a", "name": "Qingsong Cai", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6b", "name": "Zelong Huang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6c", "name": "Chuan Hao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6d", "name": "Ran Tao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6e", "name": "Xianglong Liu", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6f", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d70", "name": "Mingjie Tang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d71", "name": "Weifeng Lv", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d72", "name": "Ming Zhou", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d73", "name": "Bryan Dai", "hidden": false}], "publishedAt": "2026-06-16T00:00:00.000Z", "submittedOnDailyAt": "2026-06-17T00:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "upvotes": 113, "discussionId": "6a3201f3bc818ff14e453d74", "ai_summary": "Parallel loop Transformers achieve better code generation performance with two loops due to refined representations, while additional loops cause diminishing returns and increased positional mismatch costs.", "ai_keywords": ["Looped Transformers", "parallel loop Transformers", "cross-loop position offsets", "shared-KV gated sliding-window attention", "loop-count selection", "LoopCoder-v2", "instruction tuning", "SWE-bench", "Multi-SWE"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u5faa\u73af\u53d8\u538b\u5668\u901a\u8fc7\u91cd\u590d\u5e94\u7528\u5171\u4eab\u6a21\u5757\u6765\u63d0\u5347\u6f5c\u5728\u8ba1\u7b97\u80fd\u529b\uff0c\u4f46\u589e\u52a0\u7684\u5faa\u73af\u4f1a\u5bfc\u81f4\u5ef6\u8fdf\u548c\u5185\u5b58\u6210\u672c\u3002</li>\n    <li>\u5e76\u884c\u5faa\u73af\u53d8\u538b\u5668\uff08PLT\uff09\u901a\u8fc7\u4ea4\u53c9\u5faa\u73af\u4f4d\u7f6e\u504f\u79fb\uff08CLP\uff09\u548c\u5171\u4eab-KV\u6ed1\u52a8\u7a97\u53e3\u6ce8\u610f\u529b\u6765\u51cf\u5c11\u8fd9\u4e9b\u6210\u672c\u3002</li>\n    <li>\u7814\u7a76PLT\u7684\u5faa\u73af\u9009\u62e9\u65f6\uff0c\u9700\u8003\u8651\u989d\u5916\u5faa\u73af\u5e26\u6765\u7684\u8868\u73b0\u63d0\u5347\u4e0e\u4f4d\u7f6e\u4e0d\u5339\u914d\u7684\u4ee3\u4ef7\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u4f7f\u7528\u4e24\u4e2a\u5faa\u73af\u7684PLT\u6a21\u578b\u5728\u4ee3\u7801\u751f\u6210\u548c\u8f6f\u4ef6\u5de5\u7a0b\u7b49\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u4e8e\u65e0\u5faa\u73af\u57fa\u7ebf\uff0c\u800c\u4e09\u4e2a\u6216\u66f4\u591a\u5faa\u73af\u5219\u5bfc\u81f4\u6027\u80fd\u4e0b\u964d\u3002</li>\n    <li>PLT\u7684\u6700\u4f73\u5faa\u73af\u6b21\u6570\u4e3a\u4e24\u4e2a\uff0c\u56e0\u4e3a\u540e\u7eed\u5faa\u73af\u7684\u6536\u76ca\u9012\u51cf\u4e14\u5f15\u5165\u7684\u504f\u5dee\u6210\u672c\u589e\u52a0\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Looped Transformers use repeated blocks to improve computation but can slow down and use more memory with more loops.</li>\n    <li>Parallel loop Transformers (PLT) solve some of these issues with techniques that help manage memory and speed.</li>\n    <li>The study focuses on how many loops to use in PLT, weighing benefits against drawbacks like positional mismatches.</li>\n    <li>Training a new model called LoopCoder-v2 showed that using two loops significantly improved performance compared to no loops.</li>\n    <li>Using more than two loops led to worse results, showing that there are diminishing returns beyond this point.</li>\n</ul>"}, "publishedAt": "2026-06-15T20:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.18023.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 319, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2605.30611", "authors": [{"_id": "6a1e3aa8808ddbc3c7d43bc1", "name": "Haozhe Zhao", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc2", "user": {"_id": "637c99bbfe115289cfedfb44", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/637c99bbfe115289cfedfb44/p4uSY0TKufJfcHpvEb_ZQ.jpeg", "isPro": false, "fullname": "ssz", "user": "ssz1111", "type": "user", "name": "ssz1111"}, "name": "Shuzheng Si", "status": "claimed_verified", "statusLastChangedAt": "2026-06-02T12:09:05.856Z", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc3", "name": "Zhenhailong Wang", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc4", "name": "Zheng Wang", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc5", "name": "Liang Chen", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc6", "name": "Xiaotong Li", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc7", "name": "Zhixiang Liang", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc8", "name": "Maosong Sun", "hidden": false}, {"_id": "6a1e3aa8808ddbc3c7d43bc9", "name": "Minjia Zhang", "hidden": false}], "publishedAt": "2026-05-28T00:00:00.000Z", "submittedOnDailyAt": "2026-06-02T00:00:00.000Z", "title": "Crafter: A Multi-Agent Harness for Editable Scientific Figure Generation from Diverse Inputs", "submittedOnDailyBy": {"_id": "637c99bbfe115289cfedfb44", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/637c99bbfe115289cfedfb44/p4uSY0TKufJfcHpvEb_ZQ.jpeg", "isPro": false, "fullname": "ssz", "user": "ssz1111", "type": "user", "name": "ssz1111"}, "summary": "Scientific figures are among the most effective means of communicating complex research ideas, yet producing publication-quality illustrations remains one of the most labor-intensive parts of paper preparation. Existing automated systems each target a single figure type under text-only input, leaving the diversity of types and conditions researchers actually use unaddressed; their raster outputs further cannot be locally revised. Because scientific figures are structured compositions of discrete semantic components, the localized errors generators produce on such layouts demand not a stronger backbone but a harness. We instantiate this harness in two complementary systems: Crafter, a multi-agent harness for figure generation that generalizes across figure types and input conditions without architectural changes, and CraftEditor, which applies the same pattern to convert raster outputs into editable SVGs. Moreover, we introduce CraftBench, a benchmark spanning three figure types and four input conditions with human quality annotation. Experiments show that Crafter substantially outperforms both standalone generators and the agentic baseline on PaperBanana-Bench and CraftBench, with ablations confirming each component's independent contribution; CraftEditor faithfully converts outputs into editable SVGs that surpass all baselines. Our code and benchmark are available at https://github.com/HaozheZhao/Crafter.", "upvotes": 108, "discussionId": "6a1e3aa9808ddbc3c7d43bca", "githubRepo": "https://github.com/HaozheZhao/Crafter", "githubRepoAddedBy": "user", "ai_summary": "Automated systems for generating scientific figures face limitations in handling diverse figure types and conditions, prompting the development of multi-agent frameworks that generalize across different input scenarios and produce editable output formats.", "ai_keywords": ["multi-agent harness", "figure generation", "raster outputs", "editable SVGs", "CraftBench", "PaperBanana-Bench"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 14, "summary_zh": "<ul>\n    <li>\u79d1\u5b66\u56fe\u5f62\u662f\u4f20\u8fbe\u590d\u6742\u7814\u7a76\u601d\u60f3\u7684\u6709\u6548\u5de5\u5177\uff0c\u4f46\u5236\u4f5c\u9ad8\u8d28\u91cf\u63d2\u56fe\u975e\u5e38\u8017\u65f6\u3002</li>\n    <li>\u73b0\u6709\u7684\u81ea\u52a8\u5316\u7cfb\u7edf\u53ea\u80fd\u5904\u7406\u5355\u4e00\u7c7b\u578b\u7684\u56fe\u5f62\uff0c\u65e0\u6cd5\u6ee1\u8db3\u7814\u7a76\u4eba\u5458\u7684\u591a\u6837\u5316\u9700\u6c42\u3002</li>\n    <li>Crafter \u662f\u4e00\u79cd\u591a\u4ee3\u7406\u7cfb\u7edf\uff0c\u53ef\u4ee5\u751f\u6210\u4e0d\u540c\u7c7b\u578b\u7684\u56fe\u5f62\uff0c\u800c\u4e0d\u9700\u8981\u6539\u53d8\u67b6\u6784\u3002</li>\n    <li>CraftEditor \u5c06\u56fe\u5f62\u7684\u5149\u6805\u8f93\u51fa\u8f6c\u6362\u4e3a\u53ef\u7f16\u8f91\u7684SVG\u683c\u5f0f\u3002</li>\n    <li>CraftBench \u662f\u4e00\u4e2a\u57fa\u51c6\u6d4b\u8bd5\uff0c\u6db5\u76d6\u4e09\u79cd\u56fe\u5f62\u7c7b\u578b\u548c\u56db\u79cd\u8f93\u5165\u6761\u4ef6\uff0c\u5177\u6709\u4eba\u5de5\u8d28\u91cf\u6807\u6ce8\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Creating high-quality scientific figures is difficult and time-consuming for researchers.</li>\n    <li>Current automated systems only handle specific types of figures and cannot be easily modified.</li>\n    <li>The authors developed two systems: Crafter for generating various figure types and CraftEditor for turning images into editable formats.</li>\n    <li>A new benchmark called CraftBench was created to test these systems with human quality assessments.</li>\n    <li>Results show that Crafter and CraftEditor perform significantly better than existing methods, and their code is available online.</li>\n</ul>"}, "publishedAt": "2026-05-27T20:00:00.000Z", "title": "Crafter: A Multi-Agent Harness for Editable Scientific Figure Generation from Diverse Inputs", "summary": "Scientific figures are among the most effective means of communicating complex research ideas, yet producing publication-quality illustrations remains one of the most labor-intensive parts of paper preparation. Existing automated systems each target a single figure type under text-only input, leaving the diversity of types and conditions researchers actually use unaddressed; their raster outputs further cannot be locally revised. Because scientific figures are structured compositions of discrete semantic components, the localized errors generators produce on such layouts demand not a stronger backbone but a harness. We instantiate this harness in two complementary systems: Crafter, a multi-agent harness for figure generation that generalizes across figure types and input conditions without architectural changes, and CraftEditor, which applies the same pattern to convert raster outputs into editable SVGs. Moreover, we introduce CraftBench, a benchmark spanning three figure types and four input conditions with human quality annotation. Experiments show that Crafter substantially outperforms both standalone generators and the agentic baseline on PaperBanana-Bench and CraftBench, with ablations confirming each component's independent contribution; CraftEditor faithfully converts outputs into editable SVGs that surpass all baselines. Our code and benchmark are available at https://github.com/HaozheZhao/Crafter.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.30611.png", "numComments": 1, "submittedBy": {"_id": "637c99bbfe115289cfedfb44", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/637c99bbfe115289cfedfb44/p4uSY0TKufJfcHpvEb_ZQ.jpeg", "fullname": "ssz", "name": "ssz1111", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n  <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u4ee3\u7406\u5728\u8bb8\u591a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u826f\u597d\uff0c\u4f46\u5927\u591a\u6570\u8bc4\u4f30\u5047\u8bbe\u73af\u5883\u662f\u9759\u6001\u7684\u3002</li>\n  <li>\u771f\u5b9e\u4e16\u754c\u7684\u90e8\u7f72\u73af\u5883\u662f\u52a8\u6001\u7684\uff0c\u4ee3\u7406\u9700\u8981\u4e0d\u65ad\u8c03\u6574\u77e5\u8bc6\u3001\u6280\u80fd\u548c\u884c\u4e3a\u3002</li>\n  <li>\u6211\u4eec\u4ecb\u7ecd\u4e86EvoArena\uff0c\u4e00\u4e2a\u6a21\u62df\u73af\u5883\u53d8\u5316\u7684\u57fa\u51c6\u5957\u4ef6\uff0c\u6db5\u76d6\u7ec8\u7aef\u3001\u8f6f\u4ef6\u548c\u793e\u4ea4\u9886\u57df\u3002</li>\n  <li>\u6211\u4eec\u63d0\u51fa\u4e86EvoMem\uff0c\u4e00\u79cd\u57fa\u4e8e\u8865\u4e01\u7684\u8bb0\u5fc6\u8303\u5f0f\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u7684\u6f14\u53d8\uff0c\u4f7f\u4ee3\u7406\u80fd\u591f\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n  <li>\u5b9e\u9a8c\u8868\u660e\uff0cEvoMem\u63d0\u9ad8\u4e86EvoArena\u7684\u6027\u80fd\uff0c\u5e76\u6539\u5584\u4e86\u5176\u4ed6\u6807\u51c6\u57fa\u51c6\u7684\u51c6\u786e\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model (LLM) agents perform well in static environments, but real-world situations are constantly changing.</li>\n    <li>EvoArena is a new benchmark that simulates these dynamic changes in different domains like terminal, software, and social settings.</li>\n    <li>EvoMem is a memory system that helps agents remember and adapt to these changes effectively.</li>\n    <li>Current agents perform poorly on EvoArena, with only 39.6% accuracy, but EvoMem boosts their performance by an average of 1.5%.</li>\n    <li>Using EvoMem also improves performance on other benchmarks and helps agents handle a series of related tasks better.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.11176", "authors": [{"_id": "6a28e548e7d78ea7587e5537", "user": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "name": "Kevin Qinghong Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:42:18.205Z", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5538", "name": "Batu EI", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5539", "name": "Yuhong Shi", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553a", "name": "Pan Lu", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553b", "name": "Philip Torr", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553c", "name": "James Zou", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "submittedOnDailyBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "upvotes": 100, "discussionId": "6a28e548e7d78ea7587e553d", "projectPage": "https://data2story.github.io/", "githubRepo": "https://github.com/QinghongLin/data2story-skill", "githubRepoAddedBy": "user", "ai_summary": "A multi-agent framework automates data journalism by generating evidence-grounded, multimodal news stories while maintaining transparency and verifiability.", "ai_keywords": ["multi-agent framework", "data journalism", "evidence-grounded", "multimodal generation", "verifiability", "article generation", "data storytelling"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 45, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "summary_zh": "<ul>\n    <li>\u6570\u636e\u8bb2\u8ff0\u6545\u4e8b\uff0c\u6570\u636e\u8bb0\u8005\u7684\u4efb\u52a1\u662f\u5c06\u539f\u59cb\u4fe1\u606f\u8f6c\u5316\u4e3a\u53ef\u4fe1\u7684\u6545\u4e8b\u3002</li>\n    <li>Data2Story \u662f\u4e00\u4e2a\u591a\u4ee3\u7406\u6846\u67b6\uff0c\u6a21\u62df\u865a\u62df\u65b0\u95fb\u5ba4\uff0c\u6574\u5408\u4e0d\u540c\u4e13\u4e1a\u89d2\u8272\u3002</li>\n    <li>\u8be5\u6846\u67b6\u7684\u521b\u65b0\u5305\u62ec\uff1a\u4e00\u662f\u6bcf\u4e2a\u6570\u636e\u548c\u5185\u5bb9\u90fd\u6709\u8bc1\u636e\u652f\u6301\uff0c\u4e8c\u662f\u751f\u6210\u591a\u6a21\u6001\u6587\u7ae0\uff0c\u5982\u4e92\u52a8\u5730\u56fe\u548c\u97f3\u9891\u3002</li>\n    <li>\u5bf918\u7bc7\u6587\u7ae0\u7684\u8bc4\u4f30\u663e\u793a\uff0cData2Story \u5728\u900f\u660e\u5ea6\u548c\u53ef\u5ba1\u8ba1\u6027\u65b9\u9762\u8868\u73b0\u51fa\u8272\u3002</li>\n    <li>\u5c3d\u7ba1 Data2Story \u8868\u73b0\u826f\u597d\uff0c\u4f46\u4eba\u7c7b\u8bb0\u8005\u5728\u521b\u610f\u8bbe\u8ba1\u548c\u7f16\u8f91\u89d2\u5ea6\u4e0a\u4ecd\u6709\u4f18\u52bf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Data journalists turn raw data into trustworthy stories for non-experts, which usually requires a team and weeks of work.</li>\n    <li>Data2Story is a new tool that combines different roles in journalism into one virtual newsroom to create complete stories.</li>\n    <li>It ensures that every claim in the articles is backed by data and external references, improving trustworthiness.</li>\n    <li>Data2Story can create engaging articles using various media, like interactive maps and audio, instead of just text and static charts.</li>\n    <li>While Data2Story produces strong multimedia stories, human journalists still excel in creativity and presentation.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.11176.png", "numComments": 4, "submittedBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "fullname": "Qinghong (Kevin) Lin", "name": "KevinQHLin", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 49, "isUserFollowing": false}, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.07297", "authors": [{"_id": "6a26b590e4c258a0294923e5", "user": {"_id": "65db54e5ab2f64915c0b9cf0", "avatarUrl": "/avatars/d451523cad8c17cda603eea2961c50ad.svg", "isPro": false, "fullname": "Shaoqiu Zhang", "user": "qiushao", "type": "user", "name": "qiushao"}, "name": "Shaoqiu Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:33.488Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e6", "name": "Yuhang Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e7", "name": "Jialiang Liang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e8", "user": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "name": "Yuling Shi", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:35.921Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e9", "name": "Wenhao Zeng", "hidden": false}, {"_id": "6a26b590e4c258a0294923ea", "name": "Maoquan Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923eb", "name": "Shilin He", "hidden": false}, {"_id": "6a26b590e4c258a0294923ec", "name": "Ningyuan Xu", "hidden": false}, {"_id": "6a26b590e4c258a0294923ed", "name": "Siyu Ye", "hidden": false}, {"_id": "6a26b590e4c258a0294923ee", "name": "Kai Cai", "hidden": false}, {"_id": "6a26b590e4c258a0294923ef", "name": "Xiaodong Gu", "hidden": false}], "publishedAt": "2026-06-05T00:00:00.000Z", "submittedOnDailyAt": "2026-06-09T00:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "submittedOnDailyBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "upvotes": 98, "discussionId": "6a26b590e4c258a0294923f0", "projectPage": "https://huggingface.co/datasets/SWE-Explore-Bench/SWE-Explore-Bench", "githubRepo": "https://github.com/Qiushao-E/SWE-Explore-Bench", "githubRepoAddedBy": "user", "ai_summary": "SWE-Explore introduces a benchmark for evaluating coding agents' repository exploration capabilities by requiring ranked lists of relevant code regions within line budgets, demonstrating that agentic exploration outperforms traditional retrieval methods.", "ai_keywords": ["repository exploration", "coding agents", "SWE-bench", "SWE-Explore", "line budget", "code localization", "context retrieval", "repository understanding", "bug diagnosis", "retrieval methods", "agentic explorers", "line-level coverage", "ranking", "context-efficiency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 13, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "summary_zh": "<ul>\n    <li>\u4ecb\u7ecd\u4e86\u4e00\u4e2a\u65b0\u7684\u57fa\u51c6\u6d4b\u8bd5SWE-Explore\uff0c\u4e13\u6ce8\u4e8e\u8bc4\u4f30\u7f16\u7801\u4ee3\u7406\u7684\u4ed3\u5e93\u63a2\u7d22\u80fd\u529b\u3002</li>\n    <li>SWE-Explore\u8981\u6c42\u63a2\u7d22\u8005\u5728\u56fa\u5b9a\u7684\u884c\u6570\u9884\u7b97\u5185\uff0c\u8fd4\u56de\u76f8\u5173\u4ee3\u7801\u533a\u57df\u7684\u6392\u540d\u5217\u8868\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u6db5\u76d6\u4e8610\u79cd\u7f16\u7a0b\u8bed\u8a00\u548c203\u4e2a\u5f00\u6e90\u4ed3\u5e93\u4e2d\u7684848\u4e2a\u95ee\u9898\u3002</li>\n    <li>\u901a\u8fc7\u72ec\u7acb\u4ee3\u7406\u7684\u8def\u5f84\uff0c\u63d0\u53d6\u6bcf\u4e2a\u5b9e\u4f8b\u7684\u884c\u7ea7\u771f\u5b9e\u6570\u636e\uff0c\u4ee5\u652f\u6301\u8bc4\u4f30\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\uff0c\u7f16\u7801\u4ee3\u7406\u5728\u63a2\u7d22\u80fd\u529b\u4e0a\u660e\u663e\u4f18\u4e8e\u4f20\u7edf\u68c0\u7d22\u65b9\u6cd5\uff0c\u5c24\u5176\u5728\u884c\u7ea7\u8986\u76d6\u548c\u6392\u540d\u6548\u7387\u4e0a\u8868\u73b0\u7a81\u51fa\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>This paper introduces SWE-Explore, a new benchmark for evaluating coding agents' ability to explore code repositories.</li>\n    <li>SWE-Explore focuses on how well agents can find relevant code sections related to specific issues within a set budget of lines.</li>\n    <li>The benchmark includes 848 issues from 10 programming languages and 203 open-source repositories.</li>\n    <li>It uses ground truth data from successful agent paths to determine which code regions were consulted for issue resolution.</li>\n    <li>The study finds that modern coding agents perform better than traditional methods in terms of coverage, ranking, and efficiency when exploring code.</li>\n</ul>"}, "publishedAt": "2026-06-04T20:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.07297.png", "numComments": 1, "submittedBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "fullname": "Yuling", "name": "YerbaPage", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 105, "isUserFollowing": false}, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.19195", "authors": [{"_id": "6a3407a3fc3a8b1102d9442a", "user": {"_id": "66d0ba2420e64fc408564bbb", "avatarUrl": "/avatars/355566cfb6347750a5faab7c87fcb79c.svg", "isPro": false, "fullname": "Anduin Dan", "user": "AnduinD", "type": "user", "name": "AnduinD"}, "name": "Kangsheng Duan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:45.706Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442b", "user": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "name": "Ziyang Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:28.418Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442c", "name": "Wenyu Liu", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442d", "name": "Xiaohu Ruan", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442e", "name": "Xiaoxin Chen", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442f", "name": "Xinggang Wang", "hidden": false}], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "submittedOnDailyBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "upvotes": 97, "discussionId": "6a3407a3fc3a8b1102d94430", "projectPage": "https://hustvl.github.io/Moebius", "githubRepo": "https://github.com/hustvl/Moebius", "githubRepoAddedBy": "user", "ai_summary": "A lightweight image inpainting framework achieves high-fidelity results with significantly reduced parameters and inference time through novel local-global interaction blocks and adaptive distillation strategies.", "ai_keywords": ["diffusion backbone", "Local-\u03bb Mix Interaction", "L\u03bbMI block", "spatial contexts", "global semantic priors", "fixed-size linear matrices", "representation bottleneck", "adaptive multi-granularity distillation", "latent space", "gradient-based losses", "high-fidelity inpainting", "parameter-efficient fine-tuning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 52, "summary_zh": "<ul>\n    <li>Moebius\u662f\u4e00\u4e2a\u9ad8\u6548\u7684\u8f7b\u91cf\u7ea7\u56fe\u50cf\u4fee\u590d\u6846\u67b6\uff0c\u65e8\u5728\u964d\u4f4e\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u5b83\u901a\u8fc7\u5f15\u5165Local-\u03bb Mix Interaction (L\u03bbMI)\u6a21\u5757\u6765\u91cd\u6784\u6269\u6563\u57fa\u7840\u67b6\u6784\u3002</li>\n    <li>Moebius\u5728\u4fdd\u7559\u590d\u6742\u6f5c\u5728\u5173\u7cfb\u7684\u540c\u65f6\uff0c\u5927\u5e45\u51cf\u5c11\u4e86\u53c2\u6570\u6570\u91cf\u3002</li>\n    <li>\u91c7\u7528\u81ea\u9002\u5e94\u591a\u7c92\u5ea6\u84b8\u998f\u7b56\u7565\uff0c\u589e\u5f3a\u4e86\u6a21\u578b\u7684\u8868\u73b0\u80fd\u529b\u3002</li>\n    <li>Moebius\u4f7f\u7528\u7684\u53c2\u6570\u4e0d\u523011.9B\u76842%\uff0c\u5e76\u4e14\u63a8\u7406\u901f\u5ea6\u63d0\u9ad8\u4e86\u8d85\u8fc715\u500d\uff0c\u5c55\u73b0\u51fa\u65b0\u7684\u9ad8\u6548\u6807\u51c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The Moebius framework is a new, efficient solution for image inpainting that reduces the computational costs of large models.</li>\n    <li>It uses a specialized structure, the Local-\u03bb Mix Interaction (L\u03bbMI) block, to maintain important details while significantly reducing the number of parameters needed.</li>\n    <li>Moebius incorporates a unique distillation strategy that works within a compressed latent space to enhance image quality without heavy processing.</li>\n    <li>In tests, Moebius performed as well or better than a much larger model (FLUX.1-Fill-Dev) but with only 2% of its parameters and over 15 times faster inference time.</li>\n    <li>This represents a major advancement in creating efficient and high-quality image inpainting models.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19195.png", "numComments": 4, "submittedBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "fullname": "Ziyang Xu", "name": "Uyoung", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "isAuthorParticipating": true}]
};
